export const htmlString = "<!DOCTYPE html>\r\n<html lang=\"en\">\r\n\r\n<head>\r\n    <meta charset=\"UTF-8\">\r\n    <meta name=\"viewport\" content=\"width=device-width, initial-scale=1.0, maximum-scale=1.0, user-scalable=no\">\r\n    <title>ARDMS-Rescue Officer App</title>\r\n\r\n    <!-- Google Fonts -->\r\n    <link rel=\"preconnect\" href=\"https://fonts.googleapis.com\">\r\n    <link rel=\"preconnect\" href=\"https://fonts.gstatic.com\" crossorigin>\r\n    <link href=\"https://fonts.googleapis.com/css2?family=Outfit:wght@300;400;500;600;700;800;900&display=swap\"\r\n        rel=\"stylesheet\">\r\n\r\n    <!-- Leaflet CSS -->\r\n    <link rel=\"stylesheet\" href=\"https://unpkg.com/leaflet@1.9.4/dist/leaflet.css\" />\r\n\r\n    <!-- HTML2PDF -->\r\n    <script src=\"https://cdnjs.cloudflare.com/ajax/libs/html2pdf.js/0.10.1/html2pdf.bundle.min.js\"></script>\r\n\r\n    <style>\r\n        :root {\r\n            /* Professional Light Palette */\r\n            --primary: #0ea5e9;\r\n            --primary-dark: #0284c7;\r\n            --primary-light: #e0f2fe;\r\n            --secondary: #10b981;\r\n            --danger: #f43f5e;\r\n            --warning: #f59e0b;\r\n            --info: #6366f1;\r\n            --bg: #f8fafc;\r\n            --surface: #ffffff;\r\n            --text-main: #0f172a;\r\n            --text-muted: #64748b;\r\n            --border: #e2e8f0;\r\n            --shadow-sm: 0 1px 2px 0 rgb(0 0 0 / 0.05);\r\n            --shadow: 0 4px 6px -1px rgb(0 0 0 / 0.1), 0 2px 4px -2px rgb(0 0 0 / 0.1);\r\n            --shadow-lg: 0 10px 15px -3px rgb(0 0 0 / 0.1), 0 4px 6px -4px rgb(0 0 0 / 0.1);\r\n            --radius: 20px;\r\n        }\r\n\r\n        * {\r\n            margin: 0;\r\n            padding: 0;\r\n            box-sizing: border-box;\r\n            -webkit-tap-highlight-color: transparent;\r\n        }\r\n\r\n        body,\r\n        html {\r\n            height: 100%;\r\n            height: 100dvh;\r\n            font-family: 'Outfit', sans-serif;\r\n            background-color: #e2e8f0;\r\n            display: flex;\r\n            justify-content: center;\r\n            align-items: center;\r\n        }\r\n\r\n        /* Phone Mockup Wrapper */\r\n        .phone-mockup {\r\n            width: 400px;\r\n            max-width: 100%;\r\n            height: 100%;\r\n            max-height: 850px;\r\n            background: #1e293b;\r\n            border-radius: 40px;\r\n            padding: 12px;\r\n            box-shadow: 0 25px 50px -12px rgba(0, 0, 0, 0.5);\r\n            position: relative;\r\n            display: flex;\r\n            flex-direction: column;\r\n            flex-shrink: 0;\r\n        }\r\n\r\n        @media (max-width: 450px) {\r\n            .phone-mockup {\r\n                max-width: none;\r\n                max-height: none;\r\n                border-radius: 0;\r\n                padding: 0;\r\n            }\r\n        }\r\n\r\n        .phone-inner {\r\n            width: 100%;\r\n            height: 100%;\r\n            background: var(--bg);\r\n            border-radius: 32px;\r\n            overflow: hidden;\r\n            display: flex;\r\n            flex-direction: column;\r\n            position: relative;\r\n        }\r\n\r\n        @media (max-width: 450px) {\r\n            .phone-inner {\r\n                border-radius: 0;\r\n            }\r\n        }\r\n\r\n        /* Screen Management */\r\n        .screen {\r\n            position: absolute;\r\n            top: 0;\r\n            left: 0;\r\n            width: 100%;\r\n            height: 100%;\r\n            display: none;\r\n            flex-direction: column;\r\n            background: var(--bg);\r\n            z-index: 10;\r\n            animation: fadeIn 0.3s ease-out;\r\n        }\r\n\r\n        .screen.active {\r\n            display: flex;\r\n        }\r\n\r\n        @keyframes fadeIn {\r\n            from {\r\n                opacity: 0;\r\n                transform: translateY(10px);\r\n            }\r\n\r\n            to {\r\n                opacity: 1;\r\n                transform: translateY(0);\r\n            }\r\n        }\r\n\r\n        /* Login Screen */\r\n        #screenLogin {\r\n            justify-content: center;\r\n            align-items: center;\r\n            padding: 40px;\r\n            background: linear-gradient(135deg, #f0f9ff 0%, #e0f2fe 100%);\r\n        }\r\n\r\n        .brand-logo {\r\n            width: 90px;\r\n            height: 90px;\r\n            background: var(--surface);\r\n            border-radius: 24px;\r\n            display: flex;\r\n            align-items: center;\r\n            justify-content: center;\r\n            margin: 0 auto 24px;\r\n            box-shadow: var(--shadow-lg);\r\n            font-size: 44px;\r\n            border: 2px solid var(--primary-light);\r\n            animation: bounce 2s infinite ease-in-out;\r\n        }\r\n\r\n        @keyframes bounce {\r\n\r\n            0%,\r\n            100% {\r\n                transform: translateY(0);\r\n            }\r\n\r\n            50% {\r\n                transform: translateY(-10px);\r\n            }\r\n        }\r\n\r\n        .brand-name {\r\n            font-size: 30px;\r\n            font-weight: 900;\r\n            color: var(--text-main);\r\n            margin-bottom: 8px;\r\n        }\r\n\r\n        .brand-tagline {\r\n            font-size: 14px;\r\n            color: var(--primary);\r\n            font-weight: 700;\r\n            margin-bottom: 40px;\r\n            letter-spacing: 2px;\r\n            text-transform: uppercase;\r\n        }\r\n\r\n        .input-group {\r\n            width: 100%;\r\n            margin-bottom: 20px;\r\n            text-align: left;\r\n        }\r\n\r\n        .input-label {\r\n            font-size: 13px;\r\n            font-weight: 800;\r\n            color: var(--text-muted);\r\n            margin-bottom: 8px;\r\n            display: block;\r\n            text-transform: uppercase;\r\n        }\r\n\r\n        .input-field {\r\n            width: 100%;\r\n            padding: 18px;\r\n            border-radius: var(--radius);\r\n            border: 2px solid var(--border);\r\n            background: var(--surface);\r\n            font-family: inherit;\r\n            font-size: 16px;\r\n            font-weight: 600;\r\n            color: var(--text-main);\r\n            transition: all 0.2s;\r\n            outline: none;\r\n        }\r\n\r\n        .input-field:focus {\r\n            border-color: var(--primary);\r\n            box-shadow: 0 0 0 5px var(--primary-light);\r\n        }\r\n\r\n        .login-btn {\r\n            width: 100%;\r\n            padding: 20px;\r\n            border-radius: var(--radius);\r\n            border: none;\r\n            background: var(--primary);\r\n            color: white;\r\n            font-size: 17px;\r\n            font-weight: 900;\r\n            cursor: pointer;\r\n            box-shadow: 0 12px 20px -5px rgba(14, 165, 233, 0.4);\r\n            transition: all 0.2s;\r\n            margin-top: 10px;\r\n        }\r\n\r\n        .login-btn:active {\r\n            transform: scale(0.97);\r\n        }\r\n\r\n        /* Dashboard Styles */\r\n        .dashboard-header {\r\n            padding: 24px 20px 12px;\r\n            background: var(--surface);\r\n            display: flex;\r\n            align-items: center;\r\n            justify-content: space-between;\r\n            z-index: 100;\r\n        }\r\n\r\n        .header-profile {\r\n            display: flex;\r\n            align-items: center;\r\n            gap: 12px;\r\n        }\r\n\r\n        .avatar-box {\r\n            width: 44px;\r\n            height: 44px;\r\n            border-radius: 14px;\r\n            background: var(--primary-light);\r\n            display: flex;\r\n            align-items: center;\r\n            justify-content: center;\r\n            font-size: 24px;\r\n            border: 2px solid var(--primary);\r\n        }\r\n\r\n        .header-title-box h2 {\r\n            font-size: 17px;\r\n            font-weight: 800;\r\n            color: var(--text-main);\r\n        }\r\n\r\n        .header-title-box p {\r\n            font-size: 12px;\r\n            font-weight: 600;\r\n            color: var(--primary);\r\n        }\r\n\r\n        #map {\r\n            width: 100%;\r\n            height: 55%;\r\n            position: relative;\r\n            z-index: 50;\r\n            border-bottom: 1px solid var(--border);\r\n        }\r\n\r\n        .map-controls {\r\n            position: absolute;\r\n            top: 20px;\r\n            right: 20px;\r\n            z-index: 1000;\r\n            display: flex;\r\n            flex-direction: column;\r\n            gap: 12px;\r\n        }\r\n\r\n        .control-btn {\r\n            width: 48px;\r\n            height: 48px;\r\n            border-radius: 14px;\r\n            background: var(--surface);\r\n            border: 1px solid var(--border);\r\n            display: flex;\r\n            align-items: center;\r\n            justify-content: center;\r\n            font-size: 20px;\r\n            box-shadow: var(--shadow);\r\n            cursor: pointer;\r\n        }\r\n\r\n        .notif-section {\r\n            flex: 1;\r\n            padding: 20px;\r\n            overflow-y: auto;\r\n            background: var(--bg);\r\n        }\r\n\r\n        .notif-label {\r\n            font-size: 12px;\r\n            font-weight: 900;\r\n            color: var(--text-muted);\r\n            text-transform: uppercase;\r\n            letter-spacing: 1.5px;\r\n            margin-bottom: 16px;\r\n            display: flex;\r\n            align-items: center;\r\n            justify-content: space-between;\r\n        }\r\n\r\n        .notif-card {\r\n            background: var(--surface);\r\n            border-radius: 20px;\r\n            padding: 20px;\r\n            margin-bottom: 16px;\r\n            border: 1px solid var(--border);\r\n            box-shadow: var(--shadow-sm);\r\n            animation: slideUp 0.4s ease-out;\r\n        }\r\n\r\n        @keyframes slideUp {\r\n            from {\r\n                opacity: 0;\r\n                transform: translateY(20px);\r\n            }\r\n\r\n            to {\r\n                opacity: 1;\r\n                transform: translateY(0);\r\n            }\r\n        }\r\n\r\n        .notif-top {\r\n            display: flex;\r\n            justify-content: space-between;\r\n            align-items: center;\r\n            margin-bottom: 10px;\r\n        }\r\n\r\n        .notif-badge {\r\n            font-size: 11px;\r\n            font-weight: 900;\r\n            padding: 4px 12px;\r\n            border-radius: 30px;\r\n            text-transform: uppercase;\r\n        }\r\n\r\n        .badge-sos {\r\n            background: #fee2e2;\r\n            color: var(--danger);\r\n        }\r\n\r\n        .badge-food {\r\n            background: #fef3c7;\r\n            color: var(--warning);\r\n        }\r\n\r\n        .badge-medical {\r\n            background: #d1fae5;\r\n            color: var(--secondary);\r\n        }\r\n\r\n        .badge-critical {\r\n            background: #ede9fe;\r\n            color: var(--info);\r\n        }\r\n\r\n        .badge-group {\r\n            background: #e0e7ff;\r\n            color: #4338ca;\r\n        }\r\n\r\n        .notif-time {\r\n            font-size: 12px;\r\n            font-weight: 700;\r\n            color: var(--text-muted);\r\n        }\r\n\r\n        .notif-title {\r\n            font-size: 18px;\r\n            font-weight: 800;\r\n            color: var(--text-main);\r\n            margin-bottom: 4px;\r\n        }\r\n\r\n        .notif-loc {\r\n            font-size: 13px;\r\n            font-weight: 600;\r\n            color: var(--text-muted);\r\n            margin-bottom: 16px;\r\n        }\r\n\r\n        .notif-btns {\r\n            display: flex;\r\n            gap: 12px;\r\n        }\r\n\r\n        .btn-action {\r\n            flex: 1;\r\n            padding: 14px;\r\n            border-radius: 14px;\r\n            border: none;\r\n            font-weight: 800;\r\n            font-size: 14px;\r\n            cursor: pointer;\r\n            transition: 0.2s;\r\n        }\r\n\r\n        .btn-primary {\r\n            background: var(--primary);\r\n            color: white;\r\n        }\r\n\r\n        .btn-secondary {\r\n            background: var(--primary-light);\r\n            color: var(--primary);\r\n        }\r\n\r\n        /* Bottom Nav */\r\n        .bottom-nav {\r\n            background: var(--surface);\r\n            border-top: 1px solid var(--border);\r\n            height: 80px;\r\n            display: flex;\r\n            align-items: center;\r\n            justify-content: space-around;\r\n            padding-bottom: 15px;\r\n            z-index: 100;\r\n        }\r\n\r\n        .nav-link {\r\n            display: flex;\r\n            flex-direction: column;\r\n            align-items: center;\r\n            gap: 6px;\r\n            color: var(--text-muted);\r\n            cursor: pointer;\r\n            flex: 1;\r\n        }\r\n\r\n        .nav-link.active {\r\n            color: var(--primary);\r\n        }\r\n\r\n        .nav-link i {\r\n            font-size: 24px;\r\n            font-style: normal;\r\n        }\r\n\r\n        .nav-link span {\r\n            font-size: 10px;\r\n            font-weight: 800;\r\n            text-transform: uppercase;\r\n        }\r\n\r\n        /* History Page */\r\n        .history-content {\r\n            padding: 20px;\r\n            flex: 1;\r\n            overflow-y: auto;\r\n        }\r\n\r\n        .history-search {\r\n            background: var(--surface);\r\n            border: 2px solid var(--border);\r\n            border-radius: 16px;\r\n            padding: 14px 18px;\r\n            display: flex;\r\n            align-items: center;\r\n            gap: 12px;\r\n            margin-bottom: 24px;\r\n        }\r\n\r\n        .history-search input {\r\n            border: none;\r\n            outline: none;\r\n            width: 100%;\r\n            font-family: inherit;\r\n            font-size: 15px;\r\n            font-weight: 600;\r\n        }\r\n\r\n        .hist-item {\r\n            background: var(--surface);\r\n            border-radius: 20px;\r\n            padding: 20px;\r\n            margin-bottom: 16px;\r\n            border: 1px solid var(--border);\r\n            display: flex;\r\n            justify-content: space-between;\r\n            align-items: flex-start;\r\n        }\r\n\r\n        .hist-details h4 {\r\n            font-size: 16px;\r\n            font-weight: 800;\r\n            color: var(--text-main);\r\n            margin-bottom: 4px;\r\n        }\r\n\r\n        .hist-details p {\r\n            font-size: 12px;\r\n            font-weight: 600;\r\n            color: var(--text-muted);\r\n        }\r\n\r\n        .hist-meta {\r\n            text-align: right;\r\n        }\r\n\r\n        .hist-status {\r\n            font-size: 10px;\r\n            font-weight: 900;\r\n            padding: 4px 10px;\r\n            border-radius: 6px;\r\n            text-transform: uppercase;\r\n        }\r\n\r\n        .status-done {\r\n            background: #d1fae5;\r\n            color: var(--secondary);\r\n        }\r\n\r\n        /* Settings Page */\r\n        .settings-content {\r\n            padding: 24px;\r\n            flex: 1;\r\n            overflow-y: auto;\r\n        }\r\n\r\n        .profile-card {\r\n            text-align: center;\r\n            background: var(--surface);\r\n            padding: 30px 20px;\r\n            border-radius: 30px;\r\n            box-shadow: var(--shadow-sm);\r\n            border: 1px solid var(--border);\r\n            margin-bottom: 30px;\r\n        }\r\n\r\n        .profile-img {\r\n            width: 110px;\r\n            height: 110px;\r\n            background: var(--primary-light);\r\n            border-radius: 35px;\r\n            margin: 0 auto 20px;\r\n            display: flex;\r\n            align-items: center;\r\n            justify-content: center;\r\n            font-size: 44px;\r\n            border: 3px solid var(--primary);\r\n        }\r\n\r\n        .profile-name {\r\n            font-size: 22px;\r\n            font-weight: 900;\r\n            color: var(--text-main);\r\n            margin-bottom: 4px;\r\n        }\r\n\r\n        .profile-info {\r\n            font-size: 14px;\r\n            font-weight: 700;\r\n            color: var(--text-muted);\r\n        }\r\n\r\n        .settings-group {\r\n            background: var(--surface);\r\n            border-radius: 20px;\r\n            border: 1px solid var(--border);\r\n            overflow: hidden;\r\n            margin-bottom: 24px;\r\n        }\r\n\r\n        .settings-item {\r\n            padding: 18px 20px;\r\n            display: flex;\r\n            align-items: center;\r\n            justify-content: space-between;\r\n            border-bottom: 1px solid var(--border);\r\n            cursor: pointer;\r\n        }\r\n\r\n        .settings-item:last-child {\r\n            border-bottom: none;\r\n        }\r\n\r\n        .item-label {\r\n            display: flex;\r\n            align-items: center;\r\n            gap: 14px;\r\n            font-size: 16px;\r\n            font-weight: 700;\r\n            color: var(--text-main);\r\n        }\r\n\r\n        .item-val {\r\n            font-size: 14px;\r\n            font-weight: 600;\r\n            color: var(--primary);\r\n        }\r\n\r\n        .logout-btn {\r\n            background: #fee2e2;\r\n            color: var(--danger);\r\n            padding: 20px;\r\n            border-radius: 20px;\r\n            text-align: center;\r\n            font-weight: 900;\r\n            cursor: pointer;\r\n            margin-top: 10px;\r\n        }\r\n\r\n        /* Filter Buttons */\r\n        .filter-btn {\r\n            padding: 6px 12px;\r\n            border-radius: 12px;\r\n            border: none;\r\n            background: #f1f5f9;\r\n            color: var(--text-muted);\r\n            font-size: 12px;\r\n            font-weight: 700;\r\n            cursor: pointer;\r\n            transition: all 0.2s;\r\n        }\r\n\r\n        .filter-btn.active {\r\n            background: var(--primary);\r\n            color: white;\r\n            box-shadow: 0 4px 10px -2px rgba(14, 165, 233, 0.4);\r\n        }\r\n\r\n        /* Active Task Card (previously banner) */\r\n        .active-mission-banner {\r\n            background: var(--primary);\r\n            color: white;\r\n            padding: 20px;\r\n            border-radius: 20px;\r\n            display: none;\r\n            align-items: center;\r\n            justify-content: space-between;\r\n            margin-bottom: 24px;\r\n            box-shadow: 0 12px 24px -8px rgba(14, 165, 233, 0.5);\r\n            animation: slideUp 0.4s ease-out;\r\n            border: 1px solid rgba(255, 255, 255, 0.1);\r\n        }\r\n\r\n        .mission-info h4 {\r\n            font-size: 14px;\r\n            font-weight: 900;\r\n            text-transform: uppercase;\r\n        }\r\n\r\n        .mission-info p {\r\n            font-size: 11px;\r\n            font-weight: 700;\r\n            opacity: 0.9;\r\n        }\r\n\r\n        .btn-complete {\r\n            background: white;\r\n            color: var(--primary);\r\n            padding: 8px 16px;\r\n            border-radius: 10px;\r\n            border: none;\r\n            font-weight: 900;\r\n            font-size: 12px;\r\n            cursor: pointer;\r\n        }\r\n\r\n        /* Camera Capture Button */\r\n        .btn-camera {\r\n            background: rgba(255, 255, 255, 0.2);\r\n            border: 1.5px solid rgba(255, 255, 255, 0.6);\r\n            color: white;\r\n            width: 36px;\r\n            height: 36px;\r\n            border-radius: 10px;\r\n            font-size: 18px;\r\n            display: flex;\r\n            align-items: center;\r\n            justify-content: center;\r\n            cursor: pointer;\r\n            transition: all 0.2s;\r\n            flex-shrink: 0;\r\n        }\r\n\r\n        .btn-camera:active {\r\n            transform: scale(0.92);\r\n        }\r\n\r\n        .btn-camera.captured {\r\n            background: rgba(16, 185, 129, 0.3);\r\n            border-color: #10b981;\r\n        }\r\n\r\n        .btn-camera-card {\r\n            background: #e0f2fe;\r\n            border: 1.5px solid var(--primary);\r\n            color: var(--primary);\r\n            padding: 8px 12px;\r\n            border-radius: 10px;\r\n            font-size: 13px;\r\n            font-weight: 800;\r\n            cursor: pointer;\r\n            transition: all 0.2s;\r\n            white-space: nowrap;\r\n        }\r\n\r\n        .btn-camera-card:active {\r\n            transform: scale(0.95);\r\n        }\r\n\r\n        .btn-camera-card.captured {\r\n            background: #d1fae5;\r\n            border-color: #10b981;\r\n            color: #059669;\r\n        }\r\n\r\n        /* Loader */\r\n        .full-loader {\r\n            position: absolute;\r\n            top: 0;\r\n            left: 0;\r\n            right: 0;\r\n            bottom: 0;\r\n            background: rgba(255, 255, 255, 0.9);\r\n            display: none;\r\n            justify-content: center;\r\n            align-items: center;\r\n            z-index: 10000;\r\n        }\r\n\r\n        .spinner {\r\n            width: 48px;\r\n            height: 48px;\r\n            border: 5px solid var(--primary-light);\r\n            border-top-color: var(--primary);\r\n            border-radius: 50%;\r\n            animation: spin 1s linear infinite;\r\n        }\r\n\r\n        @keyframes spin {\r\n            to {\r\n                transform: rotate(360deg);\r\n            }\r\n        }\r\n\r\n        /* Marker UI */\r\n        .custom-marker {\r\n            width: 36px;\r\n            height: 36px;\r\n            border-radius: 50%;\r\n            border: 3px solid white;\r\n            display: flex;\r\n            align-items: center;\r\n            justify-content: center;\r\n            box-shadow: var(--shadow-lg);\r\n            color: white;\r\n            font-size: 18px;\r\n        }\r\n    </style>\r\n</head>\r\n\r\n<body>\r\n\r\n    <div class=\"phone-mockup\">\r\n        <div class=\"phone-inner\">\r\n\r\n            <!-- SCREEN 1: LOGIN -->\r\n            <div class=\"screen active\" id=\"screenLogin\">\r\n                <div class=\"brand-logo\" style=\"background:none; box-shadow:none; border:none;\">\r\n                    <img id=\"loginLogoImg\" src=\"official_rescuer_icon.png\"\r\n                        style=\"width:100%; height:100%; border-radius:24px; object-fit:cover;\">\r\n                </div>\r\n                <h1 class=\"brand-name\">ARDMS-Rescue Officer App</h1>\r\n                <p class=\"brand-tagline\">Emergency Field Operations</p>\r\n\r\n                <div class=\"input-group\">\r\n                    <label class=\"input-label\">Officer Login ID</label>\r\n                    <input type=\"text\" id=\"inpId\" class=\"input-field\" placeholder=\"Enter Phone or ID\"\r\n                        >\r\n                </div>\r\n                <div style=\"margin-bottom:20px;\">\r\n                    <label style=\"display:block; margin-bottom:8px; font-size:12px; font-weight:600; color:var(--text-muted); text-transform:uppercase;\">Access PIN</label>\r\n                    <input type=\"password\" id=\"inpPin\" class=\"input-field\" placeholder=\"Enter PIN\">\r\n                </div>\r\n                <div class=\"input-group\">\r\n                    <label class=\"input-label\">Server IP Address</label>\r\n                    <input type=\"text\" id=\"inpIp\" class=\"input-field\" placeholder=\"e.g. 192.168.1.15\" value=\"\">\r\n                </div>\r\n\r\n                <button class=\"login-btn\" onclick=\"core.login()\">LOGIN</button>\r\n                <p id=\"loginError\"\r\n                    style=\"color:var(--danger); font-size:12px; font-weight:800; margin-top:20px; display:none;\">ACCESS\r\n                    DENIED - INVALID CREDENTIALS</p>\r\n                <p\r\n                    style=\"color:var(--text-muted); font-size:11px; margin-top:30px; text-align:center; font-weight:700;\">\r\n                    Credentials are issued and managed by HQ administration.</p>\r\n            </div>\r\n\r\n            <!-- SCREEN 2: DASHBOARD -->\r\n            <div class=\"screen\" id=\"screenHome\">\r\n                <div class=\"dashboard-header\">\r\n                    <div class=\"header-profile\">\r\n                        <div class=\"avatar-box\">👨‍✈️</div>\r\n                        <div class=\"header-title-box\">\r\n                            <h2 id=\"dispName\">Officer Name</h2>\r\n                            <p id=\"dispZone\">Monitoring Active Zones</p>\r\n                        </div>\r\n                    </div>\r\n                    <div class=\"control-btn\" onclick=\"core.refresh()\">🔄</div>\r\n                </div>\r\n\r\n                <div id=\"map\">\r\n                    <div class=\"map-controls\">\r\n                        <div class=\"control-btn\" onclick=\"core.locateSelf()\">📍</div>\r\n                        <div class=\"control-btn\" onclick=\"core.toggleMapType()\">🗺️</div>\r\n                    </div>\r\n                </div>\r\n\r\n                <div class=\"notif-section\" id=\"notifSection\"\r\n                    style=\"background:transparent; box-shadow:none; padding:10px;\">\r\n                    <div class=\"active-mission-banner\" id=\"missionBanner\">\r\n                        <div class=\"mission-info\">\r\n                            <h4 id=\"missType\">Medical Rescue</h4>\r\n                            <p id=\"missLoc\">Sector 4, Block A</p>\r\n                        </div>\r\n                        <div style=\"display:flex; align-items:center; gap:8px; flex-shrink:0;\">\r\n                            <button class=\"btn-camera\" id=\"bannerCameraBtn\" title=\"Capture Completion Photo\" onclick=\"core.triggerCamera('__banner__', 'banner')\">📷</button>\r\n                            <button class=\"btn-complete\" onclick=\"core.completeMission()\">COMPLETE</button>\r\n                        </div>\r\n                    </div>\r\n\r\n                    <div class=\"notif-label\" style=\"margin-top:10px;\">\r\n                        <span>🚨 Current Critical Mission</span>\r\n                    </div>\r\n                    <div id=\"homeListCritical\">\r\n                        <!-- Critical Dispatches -->\r\n                    </div>\r\n\r\n                    <div class=\"notif-label\" style=\"margin-top:20px;\">\r\n                        <span>📦 Current Normal Mission</span>\r\n                    </div>\r\n                    <div id=\"homeListNormal\">\r\n                        <!-- Normal Dispatches -->\r\n                    </div>\r\n\r\n                    <div class=\"notif-label\" style=\"margin-top:20px;\">\r\n                        <span>📦 Grouped Mission Clusters</span>\r\n                    </div>\r\n                    <div id=\"homeListGrouped\">\r\n                        <!-- Grouped Dispatches -->\r\n                    </div>\r\n\r\n                </div>\r\n\r\n                <div class=\"bottom-nav\">\r\n                    <div class=\"nav-link active\" onclick=\"core.nav('Home')\"><i>🏠</i><span>Home</span></div>\r\n                    <div class=\"nav-link\" onclick=\"core.nav('Tasks')\"><i>📡</i><span>Current Tasks</span></div>\r\n                    <div class=\"nav-link\" onclick=\"core.nav('History')\"><i>📋</i><span>History</span></div>\r\n                    <div class=\"nav-link\" onclick=\"core.nav('Settings')\"><i>⚙️</i><span>Settings</span></div>\r\n                </div>\r\n            </div>\r\n\r\n            <!-- SCREEN 2B: CURRENT TASKS -->\r\n            <div class=\"screen\" id=\"screenTasks\">\r\n                <div class=\"dashboard-header\">\r\n                    <h2 style=\"font-size: 22px; font-weight: 900;\">Current Tasks</h2>\r\n                    <div class=\"control-btn\" onclick=\"core.refresh()\">🔄</div>\r\n                </div>\r\n\r\n                <div class=\"notif-section\" id=\"tasksSection\"\r\n                    style=\"padding: 20px; padding-bottom: 90px; flex: 1; overflow-y: auto; -webkit-overflow-scrolling: touch;\">\r\n                    <div class=\"notif-label\">\r\n                        <span>🚨 Current Critical Mission</span>\r\n                    </div>\r\n                    <div id=\"tasksListCritical\">\r\n                        <!-- Critical Dispatches -->\r\n                    </div>\r\n\r\n                    <div class=\"notif-label\" style=\"margin-top:20px;\">\r\n                        <span>📦 Current Normal Mission</span>\r\n                    </div>\r\n                    <div id=\"tasksListNormal\">\r\n                        <!-- Normal Dispatches -->\r\n                    </div>\r\n\r\n                    <div class=\"notif-label\" style=\"margin-top:20px;\">\r\n                        <span>📦 Grouped Mission Clusters</span>\r\n                    </div>\r\n                    <div id=\"tasksListGrouped\">\r\n                        <!-- Grouped Dispatches -->\r\n                    </div>\r\n\r\n                </div>\r\n\r\n                <div class=\"bottom-nav\">\r\n                    <div class=\"nav-link\" onclick=\"core.nav('Home')\"><i>🏠</i><span>Home</span></div>\r\n                    <div class=\"nav-link active\" onclick=\"core.nav('Tasks')\"><i>📡</i><span>Current Tasks</span></div>\r\n                    <div class=\"nav-link\" onclick=\"core.nav('History')\"><i>📋</i><span>History</span></div>\r\n                    <div class=\"nav-link\" onclick=\"core.nav('Settings')\"><i>⚙️</i><span>Settings</span></div>\r\n                </div>\r\n            </div>\r\n\r\n            <!-- SCREEN 3: HISTORY -->\r\n            <div class=\"screen\" id=\"screenHistory\">\r\n                <div class=\"dashboard-header\">\r\n                    <h2 style=\"font-size: 22px; font-weight: 900;\">Mission History</h2>\r\n                    <div class=\"control-btn\" onclick=\"core.nav('Home')\">✕</div>\r\n                </div>\r\n\r\n                <div class=\"history-content\">\r\n                    <div class=\"history-search\">\r\n                        <i>🔍</i>\r\n                        <input type=\"text\" id=\"histSearch\" placeholder=\"Search mission ID, type, sector...\"\r\n                            oninput=\"core.filterHistory()\">\r\n                    </div>\r\n\r\n                    <div class=\"filter-row\" style=\"display: flex; gap: 5px; margin-top: 10px; padding: 0 10px;\">\r\n                        <button class=\"filter-btn active\" onclick=\"core.setHistoryFilter('full', event)\">Full</button>\r\n                        <button class=\"filter-btn\" onclick=\"core.setHistoryFilter('day', event)\">Day</button>\r\n                        <button class=\"filter-btn\" onclick=\"core.setHistoryFilter('week', event)\">Week</button>\r\n                        <button class=\"filter-btn\" onclick=\"core.setHistoryFilter('yearly', event)\">Year</button>\r\n                        <button class=\"filter-btn\" style=\"margin-left: auto; background: var(--danger); color: white;\"\r\n                            onclick=\"core.downloadHistoryPDF()\">📄 PDF</button>\r\n                    </div>\r\n\r\n                    <div id=\"pdfContent\" style=\"padding-top: 5px; background: #fff;\">\r\n                        <div\r\n                            style=\"margin-top:15px; font-size:12px; font-weight:800; color:var(--danger); padding:0 10px;\">\r\n                            CRITICAL MISSIONS</div>\r\n                        <div id=\"histListCritical\"></div>\r\n\r\n                        <div\r\n                            style=\"margin-top:20px; font-size:12px; font-weight:800; color:var(--primary); padding:0 10px;\">\r\n                            NORMAL MISSIONS</div>\r\n                        <div id=\"histListNormal\"></div>\r\n                    </div>\r\n                </div>\r\n\r\n                <div class=\"bottom-nav\">\r\n                    <div class=\"nav-link\" onclick=\"core.nav('Home')\"><i>🏠</i><span>Home</span></div>\r\n                    <div class=\"nav-link\" onclick=\"core.nav('Tasks')\"><i>📡</i><span>Current Tasks</span></div>\r\n                    <div class=\"nav-link active\" onclick=\"core.nav('History')\"><i>📋</i><span>History</span></div>\r\n                    <div class=\"nav-link\" onclick=\"core.nav('Settings')\"><i>⚙️</i><span>Settings</span></div>\r\n                </div>\r\n            </div>\r\n\r\n            <!-- SCREEN 4: SETTINGS -->\r\n            <div class=\"screen\" id=\"screenSettings\">\r\n                <div class=\"dashboard-header\">\r\n                    <h2 style=\"font-size: 22px; font-weight: 900;\">Officer Profile</h2>\r\n                    <div class=\"control-btn\" onclick=\"core.nav('Home')\">✕</div>\r\n                </div>\r\n\r\n                <div class=\"settings-content\">\r\n                    <div class=\"profile-card\">\r\n                        <div class=\"profile-img\">👨‍✈️</div>\r\n                        <h2 class=\"profile-name\" id=\"profName\">Officer Rajan</h2>\r\n                        <p class=\"profile-info\" id=\"profId\">ID: MEM-01 • Rescue Division</p>\r\n                    </div>\r\n\r\n                    <div class=\"settings-group\">\r\n                        <div class=\"settings-item\">\r\n                            <div class=\"item-label\"><i>📱</i> Phone Number</div>\r\n                            <div class=\"item-val\" id=\"profPhone\">+91 9876543210</div>\r\n                        </div>\r\n                        <div class=\"settings-item\">\r\n                            <div class=\"item-label\"><i>🏢</i> Department</div>\r\n                            <div class=\"item-val\">Emergency Ops</div>\r\n                        </div>\r\n                        <div class=\"settings-item\">\r\n                            <div class=\"item-label\"><i>👥</i> Assigned Groups</div>\r\n                            <div class=\"item-val\" id=\"profGroups\">No Groups</div>\r\n                        </div>\r\n                    </div>\r\n\r\n                    <div class=\"settings-group\">\r\n                        <div class=\"settings-item\">\r\n                            <div class=\"item-label\"><i>🔔</i> Dispatch Alerts</div>\r\n                            <div class=\"item-val\">ACTIVE</div>\r\n                        </div>\r\n                        <div class=\"settings-item\" style=\"background: var(--primary-light);\">\r\n                            <div class=\"item-label\">\r\n                                <div id=\"syncStatusDot\"\r\n                                    style=\"width:10px; height:10px; border-radius:50%; background:var(--secondary); box-shadow:0 0 10px var(--secondary);\">\r\n                                </div>\r\n                                <i>🔄</i> Reconnect Timing\r\n                            </div>\r\n                            <div class=\"item-val\" id=\"dispSyncInterval\">15s (Admin Set)</div>\r\n                        </div>\r\n                    </div>\r\n\r\n                    <div class=\"settings-group\">\r\n                        <div class=\"settings-item\" style=\"flex-direction: column; align-items: stretch; gap: 8px; padding: 15px 20px;\">\r\n                            <div class=\"item-label\" style=\"font-weight: 800; color: var(--primary); font-size: 11px; letter-spacing: 0.5px;\"><i>📡</i> SERVER NETWORK SETTINGS</div>\r\n                            <div style=\"display: flex; gap: 8px; align-items: center; margin-top: 4px;\">\r\n                                <input type=\"text\" id=\"inpServerIp\" placeholder=\"e.g. 192.168.1.15\" \r\n                                    style=\"flex: 1; padding: 10px; border-radius: 8px; border: 1px solid var(--border); background: var(--bg-body); color: var(--text-main); font-family: 'Inter'; font-size: 14px;\">\r\n                                <button onclick=\"core.updateServerIp()\" \r\n                                    style=\"background: var(--accent); color: white; border: none; padding: 10px 16px; border-radius: 8px; font-weight: 700; font-size: 13px; cursor: pointer;\">SAVE</button>\r\n                            </div>\r\n                        </div>\r\n                    </div>\r\n\r\n                    <div class=\"logout-btn\" onclick=\"core.clearCache()\" style=\"background:var(--warning); color:var(--text-main); margin-bottom:10px;\">CLEAR APP CACHE & REFRESH</div>\r\n                    <div class=\"logout-btn\" onclick=\"core.logout()\">SECURE SESSION LOGOUT</div>\r\n\r\n                    <div\r\n                        style=\"text-align:center; margin-top:20px; color:var(--text-muted); font-size:12px; font-weight:700;\">\r\n                        PLATFORM VERSION 3.1.0-PRO<br>\r\n                        FIELD RESCUER OPERATIONS\r\n                    </div>\r\n                </div>\r\n\r\n                <div class=\"bottom-nav\">\r\n                    <div class=\"nav-link\" onclick=\"core.nav('Home')\"><i>🏠</i><span>Home</span></div>\r\n                    <div class=\"nav-link\" onclick=\"core.nav('Tasks')\"><i>📡</i><span>Current Tasks</span></div>\r\n                    <div class=\"nav-link\" onclick=\"core.nav('History')\"><i>📋</i><span>History</span></div>\r\n                    <div class=\"nav-link active\" onclick=\"core.nav('Settings')\"><i>⚙️</i><span>Settings</span></div>\r\n                </div>\r\n            </div>\r\n\r\n            <!-- LOADER -->\r\n            <div class=\"full-loader\" id=\"loader\">\r\n                <div class=\"spinner\"></div>\r\n            </div>\r\n\r\n        </div>\r\n    </div>\r\n\r\n    <!-- Hidden Camera / File Input for completion photo capture -->\r\n    <input type=\"file\" id=\"hiddenCameraInput\" accept=\"image/*\" capture=\"environment\" style=\"display:none;\">\r\n\r\n    <!-- Leaflet JS -->\r\n    <script src=\"https://unpkg.com/leaflet@1.9.4/dist/leaflet.js\"></script>\r\n\r\n    <script>\r\n\r\n        // --- OFFLINE SYNC MANAGER ---\r\n        const originalFetch = window.fetch;\r\n        window.offlineQueue = JSON.parse(localStorage.getItem('offline_queue') || '[]');\r\n        window.fetch = async function(url, options) {\r\n            const isMutation = options && ['POST', 'PUT', 'DELETE'].includes(options.method);\r\n            if (!navigator.onLine && isMutation) {\r\n                console.log('[OFFLINE] Queuing request', url);\r\n                window.offlineQueue.push({ url, options });\r\n                localStorage.setItem('offline_queue', JSON.stringify(window.offlineQueue));\r\n                return new Response(JSON.stringify({ success: true, offline: true, id: Date.now() }), { status: 200, headers: { 'Content-Type': 'application/json' } });\r\n            }\r\n            \r\n            try {\r\n                const res = await originalFetch(url, options);\r\n                if (options === undefined || options.method === 'GET' || !options.method) {\r\n                    if (url.includes('/history') || url.includes('/rescue-requests') || url.includes('/dashboard-stats') || url.includes('/zones') || url.includes('/users')) {\r\n                        const clone = res.clone();\r\n                        clone.text().then(data => {\r\n                            localStorage.setItem('cache_' + url, data);\r\n                        }).catch(() => {});\r\n                    }\r\n                }\r\n                return res;\r\n            } catch (e) {\r\n                // If the fetch fails for any reason (e.g. server unreachable despite Wi-Fi connection)\r\n                if (isMutation) {\r\n                    console.log('[OFFLINE FALLBACK] Queuing request due to fetch failure', url);\r\n                    window.offlineQueue.push({ url, options });\r\n                    localStorage.setItem('offline_queue', JSON.stringify(window.offlineQueue));\r\n                    return new Response(JSON.stringify({ success: true, offline: true, id: Date.now() }), { status: 200, headers: { 'Content-Type': 'application/json' } });\r\n                } else {\r\n                    const cached = localStorage.getItem('cache_' + url);\r\n                    if (cached) {\r\n                        return new Response(cached, { status: 200, headers: { 'Content-Type': 'application/json' } });\r\n                    }\r\n                }\r\n                throw e;\r\n            }\r\n        };\r\n\r\n        window.addEventListener('online', async () => {\r\n            console.log('[ONLINE] Syncing offline queue...');\r\n            const queue = JSON.parse(localStorage.getItem('offline_queue') || '[]');\r\n            window.offlineQueue = [];\r\n            localStorage.setItem('offline_queue', '[]');\r\n            for (const req of queue) {\r\n                try {\r\n                    await originalFetch(req.url, req.options);\r\n                } catch (e) {\r\n                    console.error('Failed to sync', req, e);\r\n                }\r\n            }\r\n            if (window.core && window.core.refresh) window.core.refresh();\r\n            if (window.core && window.core.updateNetUI) window.core.updateNetUI(true);\r\n        });\r\n        // -----------------------------\r\n\r\n\r\n        // Timezone conversion helpers\r\n        function formatLocalTime(dbTimeStr) {\r\n            if (!dbTimeStr) return '--:--';\r\n            let t = dbTimeStr.trim();\r\n            if (!t.includes('T')) t = t.replace(' ', 'T');\r\n            if (!t.endsWith('Z') && !t.includes('+')) t += 'Z';\r\n            try {\r\n                const d = new Date(t);\r\n                if (isNaN(d)) return dbTimeStr;\r\n                let h = d.getHours();\r\n                let m = d.getMinutes();\r\n                const ampm = h >= 12 ? 'PM' : 'AM';\r\n                h = h % 12;\r\n                h = h ? h : 12;\r\n                m = m < 10 ? '0' + m : m;\r\n                return h + ':' + m + ' ' + ampm;\r\n            } catch(e) { return dbTimeStr; }\r\n        }\r\n\r\n        function formatLocalDate(dbTimeStr) {\r\n            if (!dbTimeStr) return '--/--/----';\r\n            let t = dbTimeStr.trim();\r\n            if (!t.includes('T')) t = t.replace(' ', 'T');\r\n            if (!t.endsWith('Z') && !t.includes('+')) t += 'Z';\r\n            try {\r\n                const d = new Date(t);\r\n                if (isNaN(d)) return dbTimeStr;\r\n                return d.toLocaleString();\r\n            } catch(e) { return dbTimeStr; }\r\n        }\r\n\r\n        function getConvexHull(points) {\r\n            if (points.length <= 2) return points;\r\n            const pts = points.slice().sort((a, b) => a[0] !== b[0] ? a[0] - b[0] : a[1] - b[1]);\r\n            const cross = (o, a, b) => (a[0] - o[0]) * (b[1] - o[1]) - (a[1] - o[1]) * (b[0] - o[0]);\r\n            const lower = [];\r\n            for (let i = 0; i < pts.length; i++) {\r\n                while (lower.length >= 2 && cross(lower[lower.length - 2], lower[lower.length - 1], pts[i]) <= 0) lower.pop();\r\n                lower.push(pts[i]);\r\n            }\r\n            const upper = [];\r\n            for (let i = pts.length - 1; i >= 0; i--) {\r\n                while (upper.length >= 2 && cross(upper[upper.length - 2], upper[upper.length - 1], pts[i]) <= 0) upper.pop();\r\n                upper.push(pts[i]);\r\n            }\r\n            upper.pop();\r\n            lower.pop();\r\n            return lower.concat(upper);\r\n        }\r\n\r\n        function generateTacticalPolygon(coords) {\r\n            if (!coords || coords.length === 0) return [];\r\n            const offset = 0.0001; // ~10 meters\r\n            if (coords.length >= 3) {\r\n                const hull = getConvexHull(coords);\r\n                const centerLat = hull.reduce((sum, p) => sum + p[0], 0) / hull.length;\r\n                const centerLng = hull.reduce((sum, p) => sum + p[1], 0) / hull.length;\r\n                return hull.map(p => {\r\n                    const dLat = p[0] - centerLat;\r\n                    const dLng = p[1] - centerLng;\r\n                    const dist = Math.sqrt(dLat * dLat + dLng * dLng);\r\n                    if (dist === 0) return [p[0] + offset, p[1] + offset];\r\n                    const ratio = (dist + offset) / dist;\r\n                    return [centerLat + dLat * ratio, centerLng + dLng * ratio];\r\n                });\r\n            }\r\n            if (coords.length === 2) {\r\n                const bounds = L.latLngBounds(coords);\r\n                const n = bounds.getNorth() + offset;\r\n                const s = bounds.getSouth() - offset;\r\n                const e = bounds.getEast() + offset;\r\n                const w = bounds.getWest() - offset;\r\n                return [\r\n                    [n, w],\r\n                    [n, e],\r\n                    [s, e],\r\n                    [s, w]\r\n                ];\r\n            }\r\n            if (coords.length === 1) {\r\n                const lat = coords[0][0];\r\n                const lng = coords[0][1];\r\n                return [\r\n                    [lat + offset, lng - offset],\r\n                    [lat + offset, lng + offset],\r\n                    [lat - offset, lng + offset],\r\n                    [lat - offset, lng - offset]\r\n                ];\r\n            }\r\n            return [];\r\n        }\r\n\r\n        /**\r\n         * ANTIGRAVITY RESCUER PRO\r\n         * Professional Realtime Emergency Response Platform\r\n         */\r\n\r\n        const core = {\r\n            API: window.__API_BASE__ || `http://${window.location.hostname || ''}:3001/api`,\r\n            WS_URL: window.__WS_BASE__ || `ws://${window.location.hostname || ''}:3001`,\r\n            serverIp: '',\r\n            user: null,\r\n            map: null,\r\n            updateLogos() {\r\n                const ip = this.serverIp || window.location.hostname || '127.0.0.1';\r\n                const logoImg = document.getElementById('loginLogoImg');\r\n                if (logoImg) {\r\n                    logoImg.src = `http://${ip}:3001/official_rescuer_icon.png`;\r\n                }\r\n            },\r\n            rescuerMarker: null,\r\n            taskMarkers: {},\r\n            groupPerimeters: {},\r\n            activeMission: null,\r\n            interruptedMission: null,\r\n            navPolyline: null,\r\n            pos: { lat: 13.0750, lng: 80.2600 },\r\n            allHistory: [],\r\n            capturedImages: {},\r\n\r\n            init() {\r\n                // Resolve correct IP address\r\n                const isNative = window.__IS_NATIVE_APP__ || (typeof window.ReactNativeWebView !== 'undefined');\r\n                const storedIp = localStorage.getItem('serverIp');\r\n                const finalIp = storedIp || window.__SERVER_IP__ || (isNative ? '' : window.location.hostname) || '';\r\n                this.serverIp = finalIp;\r\n                this.API = finalIp ? `http://${finalIp}:3001/api` : '';\r\n                this.WS_URL = finalIp ? `ws://${finalIp}:3001` : '';\r\n                this.updateLogos();\r\n\r\n                const inpIp = document.getElementById('inpIp');\r\n                if (inpIp) inpIp.value = finalIp;\r\n                const inpServerIp = document.getElementById('inpServerIp');\r\n                if (inpServerIp) inpServerIp.value = finalIp;\r\n\r\n                this.setupIpInputListeners();\r\n\r\n                // Guarantee a completely clean login session on first launching a fresh installation or update\r\n                const APP_VERSION = '1.1.0';\r\n                const storedVersion = localStorage.getItem('appVersion');\r\n                if (storedVersion !== APP_VERSION) {\r\n                    localStorage.removeItem('rescuer_token');\r\n                    localStorage.removeItem('rescue_user_v3');\r\n                    localStorage.setItem('appVersion', APP_VERSION);\r\n                }\r\n\r\n                const saved = localStorage.getItem('rescue_user_v3');\r\n                const token = localStorage.getItem('rescuer_token');\r\n                if (saved && token && this.API) {\r\n                    this.showLoader(true);\r\n                    fetch(`${this.API}/auth/verify`, {\r\n                        headers: { 'Authorization': `Bearer ${token}` }\r\n                    }).then(res => {\r\n                        if (res.ok) {\r\n                            return res.json();\r\n                        } else {\r\n                            throw new Error('Invalid token');\r\n                        }\r\n                    }).then(data => {\r\n                        if (!data.user || data.user.role !== 'rescuer') {\r\n                            throw new Error('Unauthorized role');\r\n                        }\r\n                        this.user = data.user;\r\n                        localStorage.setItem('rescue_user_v3', JSON.stringify(this.user));\r\n                        this.showScreen('screenHome');\r\n                        this.bootstrap();\r\n                        this.showLoader(false);\r\n                    }).catch(e => {\r\n                        console.error('Verification failed:', e);\r\n                        if (!navigator.onLine) {\r\n                            // If completely offline and fetch failed, proceed with cached credentials\r\n                            this.user = JSON.parse(saved);\r\n                            this.showScreen('screenHome');\r\n                            this.bootstrap();\r\n                        } else {\r\n                            // Online but invalid token: log out\r\n                            this.logout();\r\n                        }\r\n                        this.showLoader(false);\r\n                    });\r\n                } else {\r\n                    // Make sure everything is clean if no valid session\r\n                    localStorage.removeItem('rescue_user_v3');\r\n                    localStorage.removeItem('rescuer_token');\r\n                }\r\n            },\r\n\r\n            async login() {\r\n                const phone = document.getElementById('inpId').value;\r\n                const pin = document.getElementById('inpPin').value;\r\n                const ip = document.getElementById('inpIp').value.trim();\r\n                const err = document.getElementById('loginError');\r\n\r\n                if (!ip) {\r\n                    err.innerText = \"SERVER IP ADDRESS REQUIRED\";\r\n                    err.style.display = 'block';\r\n                    return;\r\n                }\r\n\r\n                // Update server IP settings\r\n                this.updateServerIp(ip);\r\n\r\n                let localDeviceId = localStorage.getItem('rescuer_device_id');\r\n                if (!localDeviceId) {\r\n                    localDeviceId = 'RESDEV-' + Math.random().toString(36).substr(2, 9).toUpperCase();\r\n                    localStorage.setItem('rescuer_device_id', localDeviceId);\r\n                }\r\n\r\n                console.log('[LOGIN] Attempting Rescuer login...', { idOrPhone: phone, pin, deviceId: localDeviceId });\r\n                this.showLoader(true);\r\n                try {\r\n                    const res = await fetch(`${this.API}/auth/login`, {\r\n                        method: 'POST',\r\n                        headers: { 'Content-Type': 'application/json' },\r\n                        body: JSON.stringify({ idOrPhone: phone, pin, deviceId: localDeviceId })\r\n                    });\r\n                    console.log('[LOGIN] Response status:', res.status);\r\n\r\n                    if (res.ok) {\r\n                        const data = await res.json();\r\n                        if (data.user.role !== 'rescuer') {\r\n                            err.innerText = \"ACCESS DENIED - OFFICERS ONLY\";\r\n                            err.style.display = 'block';\r\n                            this.showLoader(false);\r\n                            return;\r\n                        }\r\n                        this.user = data.user;\r\n                        localStorage.setItem('rescuer_token', data.token);\r\n                        localStorage.setItem('rescue_user_v3', JSON.stringify(this.user));\r\n                        this.showScreen('screenHome');\r\n                        this.bootstrap();\r\n                    } else {\r\n                        const errData = await res.json();\r\n                        err.innerText = errData.error || \"ACCESS DENIED\";\r\n                        err.style.display = 'block';\r\n                    }\r\n                } catch (e) {\r\n                    console.error(\"Login Error:\", e);\r\n                    err.innerText = \"NETWORK ERROR - CHECK CONNECTION\";\r\n                    err.style.display = 'block';\r\n                } finally {\r\n                    this.showLoader(false);\r\n                }\r\n            },\r\n\r\n            logout() {\r\n                localStorage.removeItem('rescue_user_v3');\r\n                localStorage.removeItem('rescuer_token');\r\n                try {\r\n                    window.ReactNativeWebView.postMessage(JSON.stringify({ type: 'LOGOUT' }));\r\n                } catch(e) {}\r\n                \r\n                this.user = null;\r\n                if (this.ws) {\r\n                    try {\r\n                        this.ws.onclose = null;\r\n                        this.ws.onerror = null;\r\n                        this.ws.close();\r\n                    } catch(e) {}\r\n                    this.ws = null;\r\n                }\r\n                this.updateNetUI(false);\r\n                this.showScreen('screenLogin');\r\n                this.toast(\"LOGGED OUT\", \"🔑\");\r\n            },\r\n\r\n            updateServerIp(ip) {\r\n                if (!ip) {\r\n                    const el = document.getElementById('inpServerIp');\r\n                    ip = el ? el.value.trim() : '';\r\n                }\r\n                if (!ip) {\r\n                    const el = document.getElementById('inpIp');\r\n                    ip = el ? el.value.trim() : '';\r\n                }\r\n                if (!ip) {\r\n                    this.toast(\"INVALID IP ADDRESS\", \"⚠️\");\r\n                    return;\r\n                }\r\n                localStorage.setItem('serverIp', ip);\r\n                this.serverIp = ip;\r\n                this.API = `http://${ip}:3001/api`;\r\n                this.WS_URL = `ws://${ip}:3001`;\r\n                this.updateLogos();\r\n\r\n                // Only reconnect WebSocket dynamically if already logged in\r\n                if (this.user) {\r\n                    this.connectWS();\r\n                }\r\n\r\n                // Sync UI Inputs\r\n                const inpIp = document.getElementById('inpIp');\r\n                if (inpIp) inpIp.value = ip;\r\n                const inpServerIp = document.getElementById('inpServerIp');\r\n                if (inpServerIp) inpServerIp.value = ip;\r\n\r\n                try {\r\n                    window.ReactNativeWebView.postMessage(JSON.stringify({ type: 'UPDATE_IP', ip }));\r\n                } catch(e) {\r\n                    this.toast(\"IP SAVED - REBOOT PREVIEW TO APPLY\", \"📡\");\r\n                }\r\n            },\r\n\r\n            setupIpInputListeners() {\r\n                const handleIpInput = (e) => {\r\n                    const val = e.target.value.trim();\r\n                    const ipRegex = /^(?:[0-9]{1,3}\\.){3}[0-9]{1,3}$/;\r\n                    if (ipRegex.test(val)) {\r\n                        localStorage.setItem('serverIp', val);\r\n                        this.serverIp = val;\r\n                        this.API = `http://${val}:3001/api`;\r\n                        this.WS_URL = `ws://${val}:3001`;\r\n                        this.updateLogos();\r\n                        \r\n                        // Only reconnect WebSocket dynamically if already logged in\r\n                        if (this.user) {\r\n                            this.connectWS();\r\n                        }\r\n                        \r\n                        // Sync inputs\r\n                        const inpIp = document.getElementById('inpIp');\r\n                        if (inpIp && inpIp !== e.target) inpIp.value = val;\r\n                        const inpServerIp = document.getElementById('inpServerIp');\r\n                        if (inpServerIp && inpServerIp !== e.target) inpServerIp.value = val;\r\n\r\n                        try {\r\n                            window.ReactNativeWebView.postMessage(JSON.stringify({ type: 'UPDATE_IP', ip: val }));\r\n                        } catch(err) {}\r\n                    } else if (val === '') {\r\n                        localStorage.setItem('serverIp', '');\r\n                        this.API = '';\r\n                        this.WS_URL = '';\r\n                        try {\r\n                            window.ReactNativeWebView.postMessage(JSON.stringify({ type: 'UPDATE_IP', ip: '' }));\r\n                        } catch(err) {}\r\n                    }\r\n                };\r\n\r\n                const inpIp = document.getElementById('inpIp');\r\n                if (inpIp) inpIp.addEventListener('input', handleIpInput);\r\n                const inpServerIp = document.getElementById('inpServerIp');\r\n                if (inpServerIp) inpServerIp.addEventListener('input', handleIpInput);\r\n            },\r\n\r\n            clearCache() {\r\n                localStorage.clear();\r\n                this.user = null;\r\n                this.serverIp = '';\r\n                this.API = '';\r\n                this.WS_URL = '';\r\n                if (this.ws) {\r\n                    try {\r\n                        this.ws.onclose = null;\r\n                        this.ws.onerror = null;\r\n                        this.ws.close();\r\n                    } catch(e) {}\r\n                    this.ws = null;\r\n                }\r\n                const inpIp = document.getElementById('inpIp');\r\n                if (inpIp) inpIp.value = '';\r\n                const inpServerIp = document.getElementById('inpServerIp');\r\n                if (inpServerIp) inpServerIp.value = '';\r\n                \r\n                try {\r\n                    window.ReactNativeWebView.postMessage(JSON.stringify({ type: 'UPDATE_IP', ip: '' }));\r\n                } catch(err) {}\r\n                \r\n                this.updateNetUI(false);\r\n                this.updateLogos();\r\n                this.showScreen('screenLogin');\r\n                this.toast(\"CACHE CLEARED\", \"🧹\");\r\n            },\r\n\r\n            bootstrap() {\r\n                this.updateUI();\r\n                this.initMap();\r\n                this.refresh();\r\n                this.startSync();\r\n                this.connectWS();\r\n                this.fetchSyncSettings();\r\n                this.updateNetUI(false);\r\n\r\n                // Listen for native GPS updates from App.js\r\n                let initialFix = false;\r\n                window.addEventListener('message', (event) => {\r\n                    try {\r\n                        const msg = typeof event.data === 'string' ? JSON.parse(event.data) : event.data;\r\n                        if (msg.type === 'GPS_UPDATE' && msg.lat && msg.lng) {\r\n                            this.pos.lat = msg.lat;\r\n                            this.pos.lng = msg.lng;\r\n                            if (this.rescuerMarker) this.rescuerMarker.setLatLng([msg.lat, msg.lng]);\r\n                            if (!initialFix && this.map) {\r\n                                this.map.flyTo([msg.lat, msg.lng], 15, { animate: false });\r\n                                initialFix = true;\r\n                            }\r\n                        }\r\n                    } catch (e) {}\r\n                });\r\n            },\r\n\r\n            async fetchSyncSettings() {\r\n                try {\r\n                    const res = await fetch(`${this.API}/settings`);\r\n                    if (res.ok) {\r\n                        const settings = await res.json();\r\n                        if (settings.system_name) {\r\n                            const brandEls = document.querySelectorAll('.brand-name');\r\n                            brandEls.forEach(el => el.innerText = settings.system_name);\r\n                        }\r\n                        if (settings.refresh_interval) {\r\n                            this.refreshInterval = parseInt(settings.refresh_interval) || 10;\r\n                            const el = document.getElementById('dispSyncInterval');\r\n                            if (el) el.innerText = this.refreshInterval + 's (Sync Active)';\r\n                        } else if (settings.retry_intervals) {\r\n                            this.refreshInterval = parseInt(settings.retry_intervals.split(',')[0]) || 15;\r\n                            const el = document.getElementById('dispSyncInterval');\r\n                            if (el) el.innerText = this.refreshInterval + 's (Legacy)';\r\n                        }\r\n                    }\r\n                } catch (e) { console.error('[SYNC] Failed to fetch settings', e); }\r\n            },\r\n\r\n            refreshInterval: 15,\r\n\r\n            updateNetUI(online) {\r\n                const dot = document.getElementById('syncStatusDot');\r\n                const label = document.getElementById('dispSyncInterval');\r\n                if (dot) {\r\n                    dot.style.background = online ? 'var(--secondary)' : 'var(--danger)';\r\n                    dot.style.boxShadow = online ? '0 0 10px var(--secondary)' : '0 0 10px var(--danger)';\r\n                }\r\n                if (!online && label) {\r\n                    label.innerText = `RECONNECTING: ${this.refreshInterval}s`;\r\n                    label.style.color = 'var(--danger)';\r\n                } else if (label) {\r\n                    label.innerText = `${this.refreshInterval}s (Admin Set)`;\r\n                    label.style.color = 'var(--primary)';\r\n                }\r\n            },\r\n\r\n            updateUI() {\r\n                document.getElementById('dispName').innerText = this.user.name;\r\n                document.getElementById('profName').innerText = this.user.name;\r\n                document.getElementById('profId').innerText = `ID: ${this.user.serial_number || 'MEM-01'} • Emergency Response`;\r\n                document.getElementById('profPhone').innerText = this.user.phone;\r\n\r\n                const groupNames = (this.user.groups && this.user.groups.length > 0) ? this.user.groups.map(g => g.group_name).join(', ') : 'No Groups Assigned';\r\n                document.getElementById('profGroups').innerText = groupNames;\r\n                document.getElementById('dispZone').innerText = `Active in: ${groupNames}`;\r\n\r\n                const serverIpField = document.getElementById('inpServerIp');\r\n                if (serverIpField) {\r\n                    serverIpField.value = this.serverIp;\r\n                }\r\n            },\r\n\r\n            initMap() {\r\n                if (this.map) return;\r\n                this.map = L.map('map', { zoomControl: false }).setView([this.pos.lat, this.pos.lng], 13);\r\n\r\n                L.tileLayer('https://{s}.basemaps.cartocdn.com/rastertiles/voyager/{z}/{x}/{y}{r}.png', {\r\n                    attribution: '©Antigravity Systems'\r\n                }).addTo(this.map);\r\n\r\n                const icon = L.divIcon({\r\n                    className: 'custom-marker',\r\n                    html: `<div style=\"background:url('http://${this.serverIp || window.location.hostname || '127.0.0.1'}:3001/official_rescuer_icon.png'); background-size:cover; width:48px; height:48px; border-radius:50%; border:3px solid white; box-shadow:0 0 20px rgba(220, 38, 38, 0.6);\"></div>`,\r\n                    iconSize: [48, 48]\r\n                });\r\n\r\n                this.rescuerMarker = L.marker([this.pos.lat, this.pos.lng], { icon }).addTo(this.map);\r\n            },\r\n\r\n            showScreen(id) {\r\n                document.querySelectorAll('.screen').forEach(s => s.classList.remove('active'));\r\n                document.getElementById(id).classList.add('active');\r\n                if (id === 'screenHome' && this.map) {\r\n                    setTimeout(() => this.map.invalidateSize(), 300);\r\n                }\r\n            },\r\n\r\n            nav(tab) {\r\n                document.querySelectorAll('.nav-link').forEach(l => l.classList.remove('active'));\r\n\r\n                const updateNavUI = (index) => {\r\n                    document.querySelectorAll('.screen.active .nav-link')[index].classList.add('active');\r\n                };\r\n\r\n                if (tab === 'Home') {\r\n                    this.showScreen('screenHome');\r\n                    updateNavUI(0);\r\n                    document.getElementById('map').scrollIntoView({ behavior: 'smooth' });\r\n                } else if (tab === 'Tasks') {\r\n                    this.showScreen('screenTasks');\r\n                    updateNavUI(1);\r\n                    this.refresh();\r\n                } else if (tab === 'History') {\r\n                    this.showScreen('screenHistory');\r\n                    updateNavUI(2);\r\n                    this.loadHistory();\r\n                } else if (tab === 'Settings') {\r\n                    this.showScreen('screenSettings');\r\n                    updateNavUI(3);\r\n                }\r\n            },\r\n\r\n            async refresh() {\r\n                try {\r\n                    // 1. Sync User Profile (Groups, Status, etc.)\r\n                    if (this.user && this.user.id) {\r\n                        const resProfile = await fetch(`${this.API}/users/${this.user.id}`).catch(() => null);\r\n                        if (resProfile && resProfile.ok) {\r\n                            const updatedUser = await resProfile.json();\r\n                            this.user = { ...this.user, ...updatedUser };\r\n                            localStorage.setItem('rescue_user_v3', JSON.stringify(this.user));\r\n                            this.updateUI();\r\n                        }\r\n                    }\r\n\r\n                    // 2. Sync Combined History (Personal + Group Missions)\r\n                    const resHistory = await fetch(`${this.API}/users/${this.user.id}/combined-history`).catch(() => ({ ok: false, json: () => [] }));\r\n                    const historyData = resHistory.ok ? await resHistory.json() : [];\r\n\r\n                    // Sort: Latest on top\r\n                    historyData.sort((a, b) => new Date(b.updated_at || b.created_at) - new Date(a.updated_at || a.created_at));\r\n\r\n                    // Filter: Show all active statuses (assigned = awaiting acceptance, accepted/ongoing = in progress)\r\n                    const activeData = historyData.filter(t => t.status && !['completed', 'resolved', 'inactive', 'declined', 'cancelled'].includes(t.status.toLowerCase()));\r\n\r\n                    // Deduplicate identical tasks (Requests vs Commands)\r\n                    const reqIdsInCmds = new Set();\r\n                    activeData.forEach(t => {\r\n                        if (t.source === 'command' && t.command_payload) {\r\n                            try {\r\n                                const p = typeof t.command_payload === 'string' ? JSON.parse(t.command_payload) : t.command_payload;\r\n                                if (p.rescue_req_id) reqIdsInCmds.add(String(p.rescue_req_id));\r\n                                if (p.request_ids && Array.isArray(p.request_ids)) {\r\n                                    p.request_ids.forEach(id => reqIdsInCmds.add(String(id)));\r\n                                }\r\n                            } catch (e) {}\r\n                        }\r\n                    });\r\n                    const dedupedData = activeData.filter(t => !(t.source === 'request' && reqIdsInCmds.has(String(t.id))));\r\n\r\n                    // Check if there is an active mission that we should resume visually\r\n                    const ongoingTask = dedupedData.find(t => t.status === 'accepted' || t.status === 'ongoing' || t.status === 'in_progress');\r\n                    if (ongoingTask && !this.activeMission) {\r\n                        this.startMission(ongoingTask.id, ongoingTask.type, ongoingTask.sector, ongoingTask.lat, ongoingTask.lng, ongoingTask.source || 'request');\r\n                    }\r\n\r\n                    this.renderDispatches(dedupedData);\r\n                } catch (e) { console.error(\"Refresh Error:\", e); }\r\n            },\r\n\r\n            renderDispatches(tasks) {\r\n                const homeCrit = document.getElementById('homeListCritical');\r\n                const homeNorm = document.getElementById('homeListNormal');\r\n                const homeGrouped = document.getElementById('homeListGrouped');\r\n                const tasksCrit = document.getElementById('tasksListCritical');\r\n                const tasksNorm = document.getElementById('tasksListNormal');\r\n                const tasksGrouped = document.getElementById('tasksListGrouped');\r\n\r\n                homeCrit.innerHTML = '';\r\n                homeNorm.innerHTML = '';\r\n                if (homeGrouped) homeGrouped.innerHTML = '';\r\n                tasksCrit.innerHTML = '';\r\n                tasksNorm.innerHTML = '';\r\n                if (tasksGrouped) tasksGrouped.innerHTML = '';\r\n\r\n                // Clear old task markers from map\r\n                for (let key in this.taskMarkers) {\r\n                    if (this.taskMarkers[key]) {\r\n                        this.map.removeLayer(this.taskMarkers[key]);\r\n                    }\r\n                }\r\n                this.taskMarkers = {};\r\n\r\n                // Clear old group perimeters from map\r\n                for (let gid in this.groupPerimeters) {\r\n                    if (this.groupPerimeters[gid]) {\r\n                        this.map.removeLayer(this.groupPerimeters[gid]);\r\n                    }\r\n                }\r\n                this.groupPerimeters = {};\r\n\r\n                const groupedTasks = tasks.filter(t => {\r\n                    if (t.type === 'group') return true;\r\n                    try {\r\n                        const d = typeof t.details === 'string' ? JSON.parse(t.details) : t.details;\r\n                        return d && d.isGroup;\r\n                    } catch(e) { return false; }\r\n                });\r\n                const critTasks = tasks.filter(t => !groupedTasks.includes(t) && (t.priority === 'critical' || ['sos', 'medical', 'pregnancy', 'critical'].includes((t.type || '').toLowerCase())));\r\n                const normTasks = tasks.filter(t => !groupedTasks.includes(t) && !critTasks.includes(t));\r\n\r\n                // Draw group perimeters on map\r\n                groupedTasks.forEach(g => {\r\n                    let d = null;\r\n                    try {\r\n                        d = typeof g.details === 'string' ? JSON.parse(g.details) : g.details;\r\n                    } catch(e) {}\r\n\r\n                    if (d && d.isGroup && d.missions && d.missions.length > 0) {\r\n                        const coords = d.missions.map(m => [parseFloat(m.lat), parseFloat(m.lng)]).filter(c => !isNaN(c[0]));\r\n                        if (coords.length === 0) return;\r\n\r\n                        let style = {\r\n                            color: '#a855f7',\r\n                            fillColor: '#a855f7',\r\n                            fillOpacity: 0.1,\r\n                            dashArray: '5, 8',\r\n                            weight: 2.5\r\n                        };\r\n\r\n                        const hull = d.custom_polygon || generateTacticalPolygon(coords);\r\n                        if (hull && hull.length > 0) {\r\n                            const poly = L.polygon(hull, style).addTo(this.map);\r\n                            poly.bindPopup(`<b>${g.sector || 'Group Cluster'}</b><br>${d.missions.length} Clusters`);\r\n                            this.groupPerimeters[g.id] = poly;\r\n                        }\r\n                    }\r\n                });\r\n\r\n                if (critTasks.length === 0) {\r\n                    homeCrit.innerHTML = '<div style=\"text-align:center; padding:20px; color:var(--text-muted); font-size:12px;\">No critical alerts</div>';\r\n                    tasksCrit.innerHTML = '<div style=\"text-align:center; padding:20px; color:var(--text-muted); font-size:12px;\">No critical alerts</div>';\r\n                }\r\n                if (normTasks.length === 0) {\r\n                    homeNorm.innerHTML = '<div style=\"text-align:center; padding:20px; color:var(--text-muted); font-size:12px;\">No routine logistics</div>';\r\n                    tasksNorm.innerHTML = '<div style=\"text-align:center; padding:20px; color:var(--text-muted); font-size:12px;\">No routine logistics</div>';\r\n                }\r\n                if (groupedTasks.length === 0) {\r\n                    if (homeGrouped) homeGrouped.innerHTML = '<div style=\"text-align:center; padding:20px; color:var(--text-muted); font-size:12px;\">No grouped clusters</div>';\r\n                    if (tasksGrouped) tasksGrouped.innerHTML = '<div style=\"text-align:center; padding:20px; color:var(--text-muted); font-size:12px;\">No grouped clusters</div>';\r\n                }\r\n\r\n\r\n                tasks.forEach(t => {\r\n                    const isGroup = groupedTasks.includes(t);\r\n                    const isCrit = !isGroup && critTasks.includes(t);\r\n                    \r\n                    const targetHome = isGroup ? homeGrouped : (isCrit ? homeCrit : homeNorm);\r\n                    const targetTasks = isGroup ? tasksGrouped : (isCrit ? tasksCrit : tasksNorm);\r\n\r\n\r\n                    const isOngoing = (t.status === 'accepted' || t.status === 'ongoing' || t.status === 'in_progress');\r\n                    const isAssigned = (t.status === 'assigned' || t.status === 'pending');\r\n\r\n                    let btnHtml = '';\r\n                    let badgeHtml = '';\r\n\r\n                    if (isOngoing) {\r\n                        const hasCaptured = !!this.capturedImages[t.id];\r\n                        const cameraLabel = hasCaptured ? '✅ Photo' : '📷 Photo';\r\n                        const cameraCls = hasCaptured ? 'btn-camera-card captured' : 'btn-camera-card';\r\n                        btnHtml = `\r\n                            <button class=\"${cameraCls}\" id=\"camBtn_${t.id}\" onclick=\"core.triggerCamera('${t.id}', '${t.source}')\">${cameraLabel}</button>\r\n                            <button class=\"btn-action\" style=\"background:#ef4444; color:white; flex:1;\" onclick=\"core.completeTask('${t.id}', '${t.source}')\">COMPLETE MISSION</button>`;\r\n                        badgeHtml = `<span class=\"notif-badge\" style=\"background:var(--warning); color:white;\">ONGOING - ${t.type.toUpperCase()}</span>`;\r\n                    } else if (isAssigned) {\r\n                        btnHtml = `<button class=\"btn-action\" style=\"background:#0ea5e9; color:white;\" onclick=\"core.accept('${t.id}', '${t.type}', '${encodeURIComponent(t.sector||'')}', ${t.lat||0}, ${t.lng||0}, '${t.source||'request'}')\">✅ ACCEPT</button>\r\n                                   <button class=\"btn-action\" style=\"background:#64748b; color:white;\" onclick=\"core.declineTask('${t.id}', event)\">❌ IGNORE</button>`;\r\n                        badgeHtml = `<span class=\"notif-badge\" style=\"background:#3b82f6; color:white; animation: pulse 1.5s infinite;\">📋 ASSIGNED - AWAITING ACCEPTANCE</span>`;\r\n                    } else {\r\n                        btnHtml = `<button class=\"btn-action\" style=\"background:#0ea5e9; color:white;\" onclick=\"core.accept('${t.id}', '${t.type}', '${encodeURIComponent(t.sector||'')}', ${t.lat||0}, ${t.lng||0}, '${t.source||'request'}')\">ACCEPT</button>\r\n                                   <button class=\"btn-action\" style=\"background:#64748b; color:white;\" onclick=\"core.declineTask('${t.id}', event)\">IGNORE</button>`;\r\n                        badgeHtml = `<span class=\"notif-badge badge-${t.type}\">${t.type}</span>`;\r\n                    }\r\n\r\n                    const card = document.createElement('div');\r\n                    card.className = 'notif-card';\r\n                    if (isOngoing) card.style.borderLeft = '4px solid var(--warning)';\r\n\r\n                    let evidenceHtml = '';\r\n                    if (t.image_url) {\r\n                        evidenceHtml += `<div style=\"width:100%; height:120px; border-radius:12px; overflow:hidden; margin-bottom:12px; border:1px solid var(--border);\">\r\n                            <img src=\"http://${core.serverIp || window.location.hostname || '127.0.0.1'}:3001${t.image_url}\" style=\"width:100%; height:100%; object-fit:cover;\">\r\n                        </div>`;\r\n                    }\r\n\r\n                    let commentHtml = '';\r\n                    if (t.details) {\r\n                        try {\r\n                            const d = typeof t.details === 'string' ? JSON.parse(t.details) : t.details;\r\n                            if (d.isGroup && d.missions) {\r\n                                commentHtml = `<div style=\"background:var(--bg); border:1px solid var(--border); padding:10px; border-radius:12px; margin-bottom:12px;\">\r\n                                    <h5 style=\"font-size:12px; margin-bottom:6px; color:var(--primary); font-weight: 800;\">📦 CLUSTERED MISSIONS (${d.missions.length})</h5>`;\r\n                                d.missions.forEach(m => {\r\n                                    let reqs = '';\r\n                                    if (m.details) {\r\n                                        try {\r\n                                            const md = typeof m.details === 'string' ? JSON.parse(m.details) : m.details;\r\n                                            const items = [];\r\n                                            if (md.food) items.push(`🍞 ${md.food}`);\r\n                                            if (md.med) items.push(`💊 ${md.med}`);\r\n                                            if (md.sanitary) items.push(`🧻 ${md.sanitary}`);\r\n                                            if (md.persons) items.push(`👥 ${md.persons}`);\r\n                                            if (items.length > 0) reqs = `<br><span style=\"color:var(--primary); font-size:10px;\">Requires: ${items.join(' | ')}</span>`;\r\n                                        } catch (e) { }\r\n                                    }\r\n                                    commentHtml += `<div style=\"font-size:11px; padding:6px; background:white; border-radius:6px; margin-bottom:4px; box-shadow:var(--shadow-sm); font-weight:600;\">\r\n                                        <b style=\"color:var(--text-main);\">${m.type.toUpperCase()}</b> <span style=\"color:var(--text-muted);\">• ${m.sector}</span>${reqs}\r\n                                    </div>`;\r\n                                });\r\n                                commentHtml += `</div>`;\r\n                            } else if (d.comments) {\r\n                                commentHtml = `<p style=\"font-size:12px; color:var(--primary); font-style:italic; margin-bottom:12px; background:var(--primary-light); padding:8px; border-radius:8px;\">\"${d.comments}\"</p>`;\r\n                            }\r\n                        } catch (e) { }\r\n                    }\r\n\r\n                    card.innerHTML = `\r\n                        <div class=\"notif-top\">\r\n                            ${badgeHtml}\r\n                            <span class=\"notif-time\">${formatLocalTime(t.created_at)}</span>\r\n                        </div>\r\n                        <h4 class=\"notif-title\">${t.type.toUpperCase()} ${isCrit ? 'EMERGENCY' : 'DISPATCH'}</h4>\r\n                        <p class=\"notif-loc\">📍 ${t.sector || 'Coordinate Point'}</p>\r\n                        ${commentHtml}\r\n                        ${evidenceHtml}\r\n                        <div class=\"notif-btns\">\r\n                            ${btnHtml}\r\n                        </div>\r\n                    `;\r\n\r\n                    targetHome.appendChild(card);\r\n                    targetTasks.appendChild(card.cloneNode(true));\r\n                    this.addTaskMarker(t);\r\n                });\r\n            },\r\n\r\n            addTaskMarker(t) {\r\n                if (t.type === 'group' && t.details) {\r\n                    try {\r\n                        const d = typeof t.details === 'string' ? JSON.parse(t.details) : t.details;\r\n                        if (d.isGroup && d.missions) {\r\n                            d.missions.forEach(m => {\r\n                                const subTask = { id: `sub_${m.id}`, type: m.type, lat: m.lat, lng: m.lng, sector: m.sector };\r\n                                this.addTaskMarker(subTask);\r\n                            });\r\n                        }\r\n                    } catch (e) { }\r\n                    return;\r\n                }\r\n\r\n                if (this.taskMarkers[t.id]) return;\r\n                const colors = { sos: '#f43f5e', food: '#f59e0b', medical: '#10b981', pregnancy: '#10b981' };\r\n                const icons = { sos: '🚨', food: '🍱', medical: '🏥', pregnancy: '🤰' };\r\n\r\n                const icon = L.divIcon({\r\n                    className: 'custom-marker',\r\n                    html: `<div style=\"background:${colors[t.type] || '#6366f1'}; width:32px; height:32px; border-radius:50%; border:2px solid white; display:flex; align-items:center; justify-content:center; font-size:14px;\">${icons[t.type] || '🛡️'}</div>`,\r\n                    iconSize: [36, 36]\r\n                });\r\n\r\n                const m = L.marker([t.lat, t.lng], { icon }).addTo(this.map);\r\n                m.bindPopup(`<b>${t.type.toUpperCase()}</b><br>${t.sector}`);\r\n                this.taskMarkers[t.id] = m;\r\n            },\r\n\r\n            async accept(id, type, sector, lat, lng, source = 'request') {\r\n                this.showLoader(true);\r\n                try {\r\n                    const endpoint = source === 'command' ? 'commands' : 'rescue-requests';\r\n                    await fetch(`${this.API}/${endpoint}/${id}/status`, {\r\n                        method: 'PUT',\r\n                        headers: { 'Content-Type': 'application/json' },\r\n                        body: JSON.stringify({ status: 'accepted', rescuer_phone: this.user.phone })\r\n                    });\r\n\r\n                    const isCrit = ['sos', 'medical', 'pregnancy', 'critical'].includes(type.toLowerCase());\r\n                    // If this is a critical task and we had a normal task active, mark it as interrupted\r\n                    if (isCrit && this.activeMission && !['sos', 'medical', 'pregnancy', 'critical'].includes(this.activeMission.type.toLowerCase())) {\r\n                        this.interruptedMission = { ...this.activeMission };\r\n                        try {\r\n                            await fetch(`${this.API}/users/${this.user.id}/interrupted-task`, {\r\n                                method: 'PUT',\r\n                                headers: { 'Content-Type': 'application/json' },\r\n                                body: JSON.stringify({ task_id: this.activeMission.id }),\r\n                            });\r\n                        } catch { }\r\n                    }\r\n\r\n                    await this.startMission(id, type, sector, lat, lng, source);\r\n                } catch (e) {\r\n                    await this.startMission(id, type, sector, lat, lng); // Fallback\r\n                } finally {\r\n                    this.showLoader(false);\r\n                }\r\n            },\r\n\r\n            async startMission(id, type, sector, lat, lng, source = 'request') {\r\n                let finalLat = Number(lat);\r\n                let finalLng = Number(lng);\r\n                let finalSector = sector;\r\n\r\n                let groupCoords = [];\r\n                let isGroupMission = false;\r\n                let customGroupPolygon = null;\r\n\r\n                try {\r\n                    const resHistory = await fetch(`${this.API}/users/${this.user.id}/combined-history`);\r\n                    const historyData = await resHistory.json();\r\n                    const task = historyData.find(t => String(t.id) === String(id) && t.source === source);\r\n\r\n                    if (task && task.details) {\r\n                        const d = typeof task.details === 'string' ? JSON.parse(task.details) : task.details;\r\n                        if (d.custom_polygon) {\r\n                            customGroupPolygon = d.custom_polygon;\r\n                        }\r\n                        if (d.isGroup && d.missions && d.missions.length > 0) {\r\n                            isGroupMission = true;\r\n                            groupCoords = d.missions.map(m => [Number(m.lat), Number(m.lng)]).filter(c => !isNaN(c[0]));\r\n                            if (groupCoords.length > 0 && (!finalLat || finalLat === 0)) {\r\n                                finalLat = groupCoords[0][0];\r\n                                finalLng = groupCoords[0][1];\r\n                            }\r\n                        }\r\n                    }\r\n                } catch (e) { }\r\n\r\n                // If coming from a command update and we didn't find group details, check payload\r\n                if (source === 'command') {\r\n                    try {\r\n                        const res = await fetch(`${this.API}/commands/${id}`);\r\n                        const cmd = await res.json();\r\n                        const payload = JSON.parse(cmd.command_payload);\r\n\r\n                        if (!finalLat || finalLat === 0) {\r\n                            finalLat = Number(payload.lat) || finalLat;\r\n                            finalLng = Number(payload.lng) || finalLng;\r\n                        }\r\n\r\n                        finalSector = payload.name || payload.sector || sector;\r\n\r\n                        if (payload.custom_polygon) {\r\n                            customGroupPolygon = payload.custom_polygon;\r\n                            isGroupMission = true;\r\n                        }\r\n\r\n                        if (payload.is_group_mission && payload.missions) {\r\n                            isGroupMission = true;\r\n                            groupCoords = payload.missions.map(m => [Number(m.lat), Number(m.lng)]).filter(c => !isNaN(c[0]));\r\n                        }\r\n                    } catch (e) { console.error(e); }\r\n                }\r\n\r\n                if (isGroupMission && groupCoords.length > 0 && (!finalLat || finalLat === 0 || isNaN(finalLat))) {\r\n                    finalLat = groupCoords[0][0];\r\n                    finalLng = groupCoords[0][1];\r\n                }\r\n\r\n                this.activeMission = { id, type, sector: finalSector, lat: finalLat, lng: finalLng, source };\r\n\r\n                document.getElementById('missionBanner').style.display = 'flex';\r\n                document.getElementById('missType').innerText = `${type.toUpperCase()} MISSION`;\r\n                document.getElementById('missLoc').innerText = finalSector;\r\n\r\n                if (this.navPolyline) this.map.removeLayer(this.navPolyline);\r\n                if (this.missionZoneLayer) this.map.removeLayer(this.missionZoneLayer);\r\n\r\n                const isCrit = ['sos', 'medical', 'pregnancy', 'critical'].includes(type.toLowerCase());\r\n                const routeColor = isCrit ? 'var(--danger)' : 'var(--primary)';\r\n\r\n                this.navPolyline = L.polyline([[this.pos.lat, this.pos.lng], [Number(finalLat), Number(finalLng)]], {\r\n                    color: routeColor, weight: 6, opacity: 0.8, dashArray: '10, 15'\r\n                }).addTo(this.map);\r\n\r\n                if (isGroupMission && groupCoords.length > 0) {\r\n                    const style = {\r\n                        color: '#a855f7',\r\n                        fillColor: '#a855f7',\r\n                        fillOpacity: 0.15,\r\n                        dashArray: '5, 8',\r\n                        weight: 2.5\r\n                    };\r\n\r\n                    const getConvexHull = (points) => {\r\n                        if (points.length <= 2) return points;\r\n                        const pts = points.slice().sort((a, b) => a[0] !== b[0] ? a[0] - b[0] : a[1] - b[1]);\r\n                        const cross = (o, a, b) => (a[0] - o[0]) * (b[1] - o[1]) - (a[1] - o[1]) * (b[0] - o[0]);\r\n                        const lower = [];\r\n                        for (let i = 0; i < pts.length; i++) {\r\n                            while (lower.length >= 2 && cross(lower[lower.length - 2], lower[lower.length - 1], pts[i]) <= 0) lower.pop();\r\n                            lower.push(pts[i]);\r\n                        }\r\n                        const upper = [];\r\n                        for (let i = pts.length - 1; i >= 0; i--) {\r\n                            while (upper.length >= 2 && cross(upper[upper.length - 2], upper[upper.length - 1], pts[i]) <= 0) upper.pop();\r\n                            upper.push(pts[i]);\r\n                        }\r\n                        upper.pop();\r\n                        lower.pop();\r\n                        return lower.concat(upper);\r\n                    };\r\n\r\n                    if (groupCoords.length === 1) {\r\n                        this.missionZoneLayer = L.circle(groupCoords[0], { ...style, radius: 400 }).addTo(this.map);\r\n                    } else if (groupCoords.length === 2 && !customGroupPolygon) {\r\n                        this.missionZoneLayer = L.rectangle(L.latLngBounds(groupCoords).pad(0.2), style).addTo(this.map);\r\n                    } else {\r\n                        const hull = customGroupPolygon || getConvexHull(groupCoords);\r\n                        this.missionZoneLayer = L.polygon(hull, style).addTo(this.map);\r\n                    }\r\n\r\n                    this.missionZoneLayer.bindPopup(`\r\n                        <div style=\"font-family:'Inter'; padding:5px; text-align:center;\">\r\n                            <b style=\"color:var(--special); font-size:14px;\">${finalSector}</b><br>\r\n                            <span style=\"font-size:11px; color:var(--text-muted);\">${groupCoords.length} Tasks in Group</span><br>\r\n                            <span style=\"font-size:11px; color:var(--primary); font-weight:600;\">Status: Active</span>\r\n                        </div>\r\n                    `);\r\n                } else {\r\n                    // Fetch dynamic zone marking created by Admin\r\n                    try {\r\n                        const res = await fetch(`${this.API}/zones`);\r\n                        const zones = await res.json();\r\n                        const activeZone = zones.find(z => z.status === 'active' && z.zone_name === sector);\r\n\r\n                        if (activeZone) {\r\n                            const geo = JSON.parse(activeZone.zone_geometry);\r\n                            const latlng = geo.latlng || geo.center;\r\n                            const radius = geo.radius;\r\n\r\n                            const style = {\r\n                                color: activeZone.color || 'var(--primary)',\r\n                                fillOpacity: 0.1,\r\n                                weight: 3,\r\n                                dashArray: '5, 10'\r\n                            };\r\n\r\n                            if (geo.type === 'Circle' || geo.type === 'radius' || (latlng && radius)) {\r\n                                this.missionZoneLayer = L.circle([latlng.lat, latlng.lng], { ...style, radius: radius }).addTo(this.map);\r\n                            } else if (geo.bounds) {\r\n                                this.missionZoneLayer = L.rectangle(geo.bounds, style).addTo(this.map);\r\n                            }\r\n                        }\r\n                    } catch (e) {\r\n                        console.error(\"Failed to fetch zones\", e);\r\n                    }\r\n                }\r\n\r\n                let bounds = this.navPolyline.getBounds();\r\n                if (this.missionZoneLayer) bounds.extend(this.missionZoneLayer.getBounds());\r\n                this.map.fitBounds(bounds, { padding: [50, 50] });\r\n\r\n                this.nav('Home');\r\n                this.toast('MISSION COMMENCED - NAVIGATING', '🚀');\r\n            },\r\n\r\n            async completeMission() {\r\n                if (!this.activeMission) return;\r\n                // Merge banner capture into the active mission ID slot\r\n                if (this.capturedImages['__banner__'] && !this.capturedImages[this.activeMission.id]) {\r\n                    this.capturedImages[this.activeMission.id] = this.capturedImages['__banner__'];\r\n                    delete this.capturedImages['__banner__'];\r\n                }\r\n                await this.completeTask(this.activeMission.id, this.activeMission.source);\r\n            },\r\n\r\n            // ───────────────────────────────────────────────────\r\n            // CAMERA CAPTURE & CANVAS COMPRESSION\r\n            // ───────────────────────────────────────────────────\r\n\r\n            triggerCamera(id, source) {\r\n                if (window.ReactNativeWebView) {\r\n                    // Send to native bridge\r\n                    window.ReactNativeWebView.postMessage(JSON.stringify({\r\n                        type: 'CAPTURE_IMAGE',\r\n                        taskId: id,\r\n                        source: source\r\n                    }));\r\n                    return;\r\n                }\r\n\r\n                const input = document.getElementById('hiddenCameraInput');\r\n                if (!input) return;\r\n\r\n                // Detach previous listener to avoid stacking\r\n                input.onchange = null;\r\n\r\n                input.onchange = async (e) => {\r\n                    const file = e.target.files[0];\r\n                    if (!file) return;\r\n                    input.value = ''; // Reset so same file can be re-chosen\r\n\r\n                    try {\r\n                        const base64 = await this._compressImage(file, 1280, 720, 500 * 1024);\r\n                        this.capturedImages[id] = base64;\r\n\r\n                        // Update banner camera button icon\r\n                        const bannerBtn = document.getElementById('bannerCameraBtn');\r\n                        if (bannerBtn && (id === '__banner__' || (this.activeMission && String(this.activeMission.id) === String(id)))) {\r\n                            bannerBtn.textContent = '✅';\r\n                            bannerBtn.classList.add('captured');\r\n                        }\r\n\r\n                        // Update card camera button\r\n                        const cardBtn = document.getElementById('camBtn_' + id);\r\n                        if (cardBtn) {\r\n                            cardBtn.textContent = '✅ Photo';\r\n                            cardBtn.classList.add('captured');\r\n                        }\r\n\r\n                        this.toast('📷 Photo attached!', '✅');\r\n                    } catch (err) {\r\n                        console.error('[Camera] Compression failed:', err);\r\n                        this.toast('Photo capture failed', '❌');\r\n                    }\r\n                };\r\n\r\n                input.click();\r\n            },\r\n\r\n            // Compress & resize an image File to JPEG base64 ≤ maxBytes\r\n            _compressImage(file, maxW, maxH, maxBytes) {\r\n                return new Promise((resolve, reject) => {\r\n                    const reader = new FileReader();\r\n                    reader.onload = (e) => {\r\n                        const img = new Image();\r\n                        img.onload = () => {\r\n                            let w = img.naturalWidth;\r\n                            let h = img.naturalHeight;\r\n\r\n                            // Downscale to fit within maxW x maxH\r\n                            if (w > maxW || h > maxH) {\r\n                                const ratio = Math.min(maxW / w, maxH / h);\r\n                                w = Math.floor(w * ratio);\r\n                                h = Math.floor(h * ratio);\r\n                            }\r\n\r\n                            const canvas = document.createElement('canvas');\r\n                            canvas.width = w;\r\n                            canvas.height = h;\r\n                            const ctx = canvas.getContext('2d');\r\n                            ctx.drawImage(img, 0, 0, w, h);\r\n\r\n                            // Iteratively lower quality until under maxBytes\r\n                            let quality = 0.85;\r\n                            let dataUrl;\r\n                            do {\r\n                                dataUrl = canvas.toDataURL('image/jpeg', quality);\r\n                                const byteLen = Math.ceil((dataUrl.length - dataUrl.indexOf(',') - 1) * 0.75);\r\n                                if (byteLen <= maxBytes || quality <= 0.2) break;\r\n                                quality -= 0.1;\r\n                            } while (true);\r\n\r\n                            resolve(dataUrl); // full data URL\r\n                        };\r\n                        img.onerror = reject;\r\n                        img.src = e.target.result;\r\n                    };\r\n                    reader.onerror = reject;\r\n                    reader.readAsDataURL(file);\r\n                });\r\n            },\r\n            // ───────────────────────────────────────────────────\r\n\r\n            async completeTask(id, source = 'request') {\r\n                // ── Photo verification gate (Now Optional) ───────────────\r\n                const photoBase64 = this.capturedImages[id] || this.capturedImages['__banner__'] || null;\r\n                // ─────────────────────────────────────────────────────────\r\n\r\n                this.showLoader(true);\r\n                try {\r\n                    const endpoint = (source === 'command' || this.activeMission?.source === 'command') ? 'commands' : 'rescue-requests';\r\n                    await fetch(`${this.API}/${endpoint}/${id}/status`, {\r\n                        method: 'PUT',\r\n                        headers: { 'Content-Type': 'application/json' },\r\n                        body: JSON.stringify({\r\n                            status: 'completed',\r\n                            rescuer_phone: this.user.phone,\r\n                            completion_image: photoBase64\r\n                        })\r\n                    });\r\n\r\n                    // Clear captured image after successful submit\r\n                    delete this.capturedImages[id];\r\n                    delete this.capturedImages['__banner__'];\r\n\r\n                    this.toast('MISSION SUCCESSFUL', '✅');\r\n\r\n                    // --- LOCAL HISTORY INJECTION ---\r\n                    try {\r\n                        const histCacheKey = 'cache_' + this.API + '/users/' + this.user.id + '/combined-history';\r\n                        let cachedHist = JSON.parse(localStorage.getItem(histCacheKey) || '[]');\r\n                        let existing = cachedHist.find(h => String(h.id) === String(id) && h.source === (source === 'command' ? 'command' : 'request'));\r\n                        if (existing) {\r\n                            existing.status = 'completed';\r\n                            existing.updated_at = new Date().toISOString();\r\n                        } else if (this.activeMission) {\r\n                            cachedHist.push({\r\n                                id: id,\r\n                                type: this.activeMission.type || 'unknown',\r\n                                sector: this.activeMission.sector || 'Unknown Sector',\r\n                                lat: this.activeMission.lat,\r\n                                lng: this.activeMission.lng,\r\n                                source: (source === 'command' ? 'command' : 'request'),\r\n                                status: 'completed',\r\n                                created_at: new Date().toISOString(),\r\n                                updated_at: new Date().toISOString(),\r\n                                priority: ['sos', 'medical', 'pregnancy', 'critical'].includes((this.activeMission.type || '').toLowerCase()) ? 'critical' : 'normal'\r\n                            });\r\n                        }\r\n                        localStorage.setItem(histCacheKey, JSON.stringify(cachedHist));\r\n                    } catch (err) { console.error(\"History cache update failed\", err); }\r\n                    // -------------------------------\r\n\r\n                    if (this.activeMission && String(this.activeMission.id) === String(id)) {\r\n                        this.endMission();\r\n                    } else {\r\n                        if (this.taskMarkers[id]) this.map.removeLayer(this.taskMarkers[id]);\r\n                        delete this.taskMarkers[id];\r\n                        this.refresh();\r\n                    }\r\n\r\n                    // If we just completed a critical mission and have an interrupted task, reopen it\r\n                    const isCritCompletion = ['sos', 'medical', 'pregnancy', 'critical'].includes(this.activeMission?.type?.toLowerCase() || '');\r\n                    if (isCritCompletion && this.interruptedMission) {\r\n                        setTimeout(async () => {\r\n                            const restored = this.interruptedMission;\r\n                            this.interruptedMission = null;\r\n                            this.toast(\"Restoring interrupted normal task...\", '🔄');\r\n\r\n                            // Clear interrupted task in backend\r\n                            fetch(`${this.API}/users/${this.user.id}/interrupted-task`, {\r\n                                method: 'PUT',\r\n                                headers: { 'Content-Type': 'application/json' },\r\n                                body: JSON.stringify({ task_id: null }),\r\n                            }).catch(() => { });\r\n\r\n                            await this.startMission(restored.id, restored.type, restored.sector, restored.lat, restored.lng);\r\n                        }, 2000);\r\n                    }\r\n                } catch (e) {\r\n                    this.toast('MISSION COMPLETED (OFFLINE)', '✅');\r\n\r\n                    // --- LOCAL HISTORY INJECTION (OFFLINE FALLBACK) ---\r\n                    try {\r\n                        const histCacheKey = 'cache_' + this.API + '/users/' + this.user.id + '/combined-history';\r\n                        let cachedHist = JSON.parse(localStorage.getItem(histCacheKey) || '[]');\r\n                        let existing = cachedHist.find(h => String(h.id) === String(id) && h.source === (source === 'command' ? 'command' : 'request'));\r\n                        if (existing) {\r\n                            existing.status = 'completed';\r\n                            existing.updated_at = new Date().toISOString();\r\n                        } else if (this.activeMission) {\r\n                            cachedHist.push({\r\n                                id: id,\r\n                                type: this.activeMission.type || 'unknown',\r\n                                sector: this.activeMission.sector || 'Unknown Sector',\r\n                                lat: this.activeMission.lat,\r\n                                lng: this.activeMission.lng,\r\n                                source: (source === 'command' ? 'command' : 'request'),\r\n                                status: 'completed',\r\n                                created_at: new Date().toISOString(),\r\n                                updated_at: new Date().toISOString(),\r\n                                priority: ['sos', 'medical', 'pregnancy', 'critical'].includes((this.activeMission.type || '').toLowerCase()) ? 'critical' : 'normal'\r\n                            });\r\n                        }\r\n                        localStorage.setItem(histCacheKey, JSON.stringify(cachedHist));\r\n                    } catch (err) { console.error(\"History cache update failed\", err); }\r\n                    // --------------------------------------------------\r\n\r\n                    if (this.activeMission && String(this.activeMission.id) === String(id)) this.endMission();\r\n                } finally {\r\n                    this.showLoader(false);\r\n                }\r\n            },\r\n\r\n            declineTask(id, event) {\r\n                this.toast('Task Ignored', 'ℹ️');\r\n                if (event && event.target) {\r\n                    const card = event.target.closest('.notif-card');\r\n                    if (card) card.remove();\r\n                }\r\n                if (this.taskMarkers[id]) {\r\n                    this.map.removeLayer(this.taskMarkers[id]);\r\n                    delete this.taskMarkers[id];\r\n                }\r\n                if (this.groupPerimeters[id]) {\r\n                    this.map.removeLayer(this.groupPerimeters[id]);\r\n                    delete this.groupPerimeters[id];\r\n                }\r\n            },\r\n\r\n            endMission() {\r\n                document.getElementById('missionBanner').style.display = 'none';\r\n                if (this.navPolyline) this.map.removeLayer(this.navPolyline);\r\n                if (this.missionZoneLayer) {\r\n                    this.map.removeLayer(this.missionZoneLayer);\r\n                    this.missionZoneLayer = null;\r\n                }\r\n                if (this.taskMarkers[this.activeMission.id]) this.map.removeLayer(this.taskMarkers[this.activeMission.id]);\r\n                delete this.taskMarkers[this.activeMission.id];\r\n                this.activeMission = null;\r\n                this.refresh();\r\n                this.map.setView([this.pos.lat, this.pos.lng], 14);\r\n                this.nav('Tasks');\r\n            },\r\n\r\n            async loadHistory() {\r\n                const listCrit = document.getElementById('histListCritical');\r\n                const listNorm = document.getElementById('histListNormal');\r\n                if (listCrit) listCrit.innerHTML = '<div style=\"text-align:center; padding:20px;\"><div class=\"spinner\" style=\"width:24px; height:24px; margin:0 auto;\"></div></div>';\r\n                if (listNorm) listNorm.innerHTML = '';\r\n\r\n                let rawHistory = [];\r\n                try {\r\n                    const res = await fetch(`${this.API}/users/${this.user.id}/combined-history`);\r\n                    rawHistory = await res.json();\r\n                    \r\n                    // Update cache on success\r\n                    if (Array.isArray(rawHistory)) {\r\n                        try {\r\n                            const histCacheKey = 'cache_' + this.API + '/users/' + this.user.id + '/combined-history';\r\n                            localStorage.setItem(histCacheKey, JSON.stringify(rawHistory));\r\n                        } catch(e) {}\r\n                    }\r\n                } catch (e) {\r\n                    console.error('Fetch history failed:', e);\r\n                }\r\n\r\n                // Fallback to cache if rawHistory is not an array or is empty\r\n                if (!Array.isArray(rawHistory) || rawHistory.length === 0) {\r\n                    const histCacheKey = 'cache_' + this.API + '/users/' + this.user.id + '/combined-history';\r\n                    const cached = localStorage.getItem(histCacheKey);\r\n                    if (cached) {\r\n                        try {\r\n                            rawHistory = JSON.parse(cached);\r\n                        } catch(err) {}\r\n                    }\r\n                }\r\n\r\n                if (!Array.isArray(rawHistory)) {\r\n                    rawHistory = [];\r\n                }\r\n\r\n                try {\r\n                    rawHistory.sort((a, b) => new Date(b.updated_at || b.created_at || b.time) - new Date(a.updated_at || a.created_at || a.time));\r\n                    \r\n                    // Deduplicate identical tasks (Requests vs Commands) from history\r\n                    const reqIdsInCmds = new Set();\r\n                    rawHistory.forEach(t => {\r\n                        if (t.source === 'command' && t.command_payload) {\r\n                            try {\r\n                                const p = typeof t.command_payload === 'string' ? JSON.parse(t.command_payload) : t.command_payload;\r\n                                if (p.rescue_req_id) reqIdsInCmds.add(String(p.rescue_req_id));\r\n                                if (p.request_ids && Array.isArray(p.request_ids)) {\r\n                                    p.request_ids.forEach(id => reqIdsInCmds.add(String(id)));\r\n                                }\r\n                            } catch (e) {}\r\n                        }\r\n                    });\r\n                    const dedupedHistory = rawHistory.filter(t => !(t.source === 'request' && reqIdsInCmds.has(String(t.id))));\r\n                    this.allHistory = dedupedHistory;\r\n                    this.renderHistory(this.allHistory);\r\n                } catch (err) {\r\n                    console.error('Sorting or rendering history failed:', err);\r\n                    if (listCrit) listCrit.innerHTML = '<div style=\"text-align:center; padding:40px; color:var(--text-muted);\">Failed to load mission logs.</div>';\r\n                }\r\n            },\r\n\r\n            renderHistory(items) {\r\n                const listCrit = document.getElementById('histListCritical');\r\n                const listNorm = document.getElementById('histListNormal');\r\n\r\n                listCrit.innerHTML = '';\r\n                listNorm.innerHTML = '';\r\n\r\n                if (items.length === 0) {\r\n                    listCrit.innerHTML = '<div style=\"text-align:center; padding:20px; color:var(--text-muted); font-size:12px;\">No history found</div>';\r\n                    listNorm.innerHTML = '<div style=\"text-align:center; padding:20px; color:var(--text-muted); font-size:12px;\">No history found</div>';\r\n                    return;\r\n                }\r\n\r\n                items.forEach(h => {\r\n                    const safeType = (h.type || 'unknown').toLowerCase();\r\n                    const isCrit = h.priority === 'critical' || ['sos', 'medical', 'pregnancy', 'critical'].includes(safeType);\r\n                    const targetList = isCrit ? listCrit : listNorm;\r\n\r\n                    const card = document.createElement('div');\r\n                    card.className = 'hist-item';\r\n                    const sourcePrefix = h.source === 'command' ? 'CMD' : 'REQ';\r\n                    \r\n                    let histEvidence = '';\r\n                    const displayImage = h.completion_image_url || h.image_url;\r\n                    if (displayImage) {\r\n                        const serverBase = this.API.replace('/api', '');\r\n                        histEvidence = `<div style=\"width:50px; height:50px; border-radius:8px; overflow:hidden; border:1px solid var(--border); margin-left:10px;\">\r\n                            <img src=\"${serverBase}${displayImage}\" style=\"width:100%; height:100%; object-fit:cover;\">\r\n                        </div>`;\r\n                    }\r\n\r\n                    let commentHtml = '';\r\n                    if (h.details) {\r\n                        try {\r\n                            const d = typeof h.details === 'string' ? JSON.parse(h.details) : h.details;\r\n                            if (d.comments) {\r\n                                commentHtml = `<p style=\"font-size:10px; color:var(--primary); font-style:italic; margin-top:6px; border-left: 2px solid var(--primary); padding-left: 6px;\">\"${d.comments}\"</p>`;\r\n                            }\r\n                        } catch (e) {\r\n                            if (h.details.length > 0) commentHtml = `<p style=\"font-size:10px; color:var(--primary); font-style:italic; margin-top:6px; border-left: 2px solid var(--primary); padding-left: 6px;\">\"${h.details}\"</p>`;\r\n                        }\r\n                    }\r\n\r\n                    const safeStatus = (h.status || '').toLowerCase();\r\n                    let badgeBg = '#f1f5f9';\r\n                    let badgeColor = '#475569';\r\n                    if (['completed', 'resolved', 'done', 'success'].includes(safeStatus)) {\r\n                        badgeBg = '#d1fae5';\r\n                        badgeColor = 'var(--secondary)';\r\n                    } else if (['declined', 'cancelled', 'rejected', 'failed'].includes(safeStatus)) {\r\n                        badgeBg = '#fee2e2';\r\n                        badgeColor = '#991b1b';\r\n                    } else if (['assigned', 'pending'].includes(safeStatus)) {\r\n                        badgeBg = '#fef3c7';\r\n                        badgeColor = '#92400e';\r\n                    } else if (['accepted', 'ongoing', 'in_progress', 'moving'].includes(safeStatus)) {\r\n                        badgeBg = '#dbeafe';\r\n                        badgeColor = '#1e40af';\r\n                    }\r\n\r\n                    let timeLabel = 'Finished';\r\n                    if (['assigned', 'pending', 'accepted', 'ongoing', 'in_progress', 'moving'].includes(safeStatus)) {\r\n                        timeLabel = 'Updated';\r\n                    }\r\n\r\n                    const recordTime = h.updated_at || h.created_at || h.time;\r\n\r\n                    card.innerHTML = `\r\n                        <div class=\"hist-details\" style=\"flex:1;\">\r\n                            <h4>${(h.type || 'unknown').toUpperCase()} • ${h.sector || ''}</h4>\r\n                            <p>ID: #${sourcePrefix}-${h.id} • ${formatLocalDate(recordTime)}</p>\r\n                            <p style=\"margin-top:4px; font-style:italic;\">${timeLabel}: ${formatLocalTime(recordTime)}</p>\r\n                            ${commentHtml}\r\n                        </div>\r\n                        ${histEvidence}\r\n                        <div class=\"hist-meta\" style=\"margin-left:10px;\">\r\n                            <span class=\"hist-status\" style=\"background: ${badgeBg}; color: ${badgeColor};\">${h.status}</span>\r\n                        </div>\r\n                    `;\r\n                    targetList.appendChild(card);\r\n                });\r\n            },\r\n\r\n            historyFilterRange: 'full',\r\n\r\n            setHistoryFilter(range, event) {\r\n                this.historyFilterRange = range;\r\n                document.querySelectorAll('.filter-btn').forEach(btn => btn.classList.remove('active'));\r\n                if (event && event.currentTarget) {\r\n                    event.currentTarget.classList.add('active');\r\n                }\r\n                this.filterHistory();\r\n            },\r\n\r\n            filterHistory() {\r\n                const q = document.getElementById('histSearch').value.toLowerCase();\r\n                const now = new Date();\r\n\r\n                const filtered = this.allHistory.filter(h => {\r\n                    const matchQ = h.type.toLowerCase().includes(q) ||\r\n                        (h.sector && h.sector.toLowerCase().includes(q)) ||\r\n                        String(h.id).includes(q);\r\n\r\n                    let matchTime = true;\r\n                    if (this.historyFilterRange !== 'full') {\r\n                        const hDate = new Date(h.updated_at);\r\n                        const diffTime = Math.abs(now - hDate);\r\n                        const diffDays = Math.ceil(diffTime / (1000 * 60 * 60 * 24));\r\n\r\n                        if (this.historyFilterRange === 'day' && diffDays > 1) matchTime = false;\r\n                        if (this.historyFilterRange === 'week' && diffDays > 7) matchTime = false;\r\n                        if (this.historyFilterRange === 'yearly' && diffDays > 365) matchTime = false;\r\n                    }\r\n\r\n                    return matchQ && matchTime;\r\n                });\r\n                this.renderHistory(filtered);\r\n            },\r\n\r\n            downloadHistoryPDF() {\r\n                const element = document.getElementById('pdfContent');\r\n                const opt = {\r\n                    margin: 0.5,\r\n                    filename: `Mission_History_${new Date().toISOString().split('T')[0]}.pdf`,\r\n                    image: { type: 'jpeg', quality: 0.98 },\r\n                    html2canvas: { scale: 2 },\r\n                    jsPDF: { unit: 'in', format: 'letter', orientation: 'portrait' }\r\n                };\r\n                if (window.html2pdf) {\r\n                    if (window.ReactNativeWebView) {\r\n                        this.toast(\"Preparing PDF for save...\", '📄');\r\n                        html2pdf().set(opt).from(element).outputPdf('datauristring').then((pdfBase64) => {\r\n                            window.ReactNativeWebView.postMessage(JSON.stringify({\r\n                                type: 'DOWNLOAD_PDF',\r\n                                filename: opt.filename,\r\n                                base64: pdfBase64\r\n                            }));\r\n                        });\r\n                    } else {\r\n                        html2pdf().set(opt).from(element).save();\r\n                    }\r\n                } else {\r\n                    window.print();\r\n                }\r\n            },\r\n\r\n            commandState: {},\r\n            syncTimer: null,\r\n            refreshInterval: 10,\r\n\r\n            startSync() {\r\n                // Initialize real geolocation tracking\r\n                const startSimulation = () => {\r\n                    if (!this.simTimer) {\r\n                        this.simTimer = setInterval(() => {\r\n                            if (this.activeMission && this.activeMission.lat) {\r\n                                const dLat = this.activeMission.lat - this.pos.lat;\r\n                                const dLng = this.activeMission.lng - this.pos.lng;\r\n                                const dist = Math.sqrt(dLat * dLat + dLng * dLng);\r\n                                if (dist > 0.0001) {\r\n                                    this.pos.lat += dLat * 0.05; // Move 5% of the distance every 2 seconds\r\n                                    this.pos.lng += dLng * 0.05;\r\n                                }\r\n                            } else {\r\n                                // Random drift if no mission\r\n                                this.pos.lat += (Math.random() - 0.5) * 0.0005;\r\n                                this.pos.lng += (Math.random() - 0.5) * 0.0005;\r\n                            }\r\n                            if (this.rescuerMarker) this.rescuerMarker.setLatLng([this.pos.lat, this.pos.lng]);\r\n                            if (this.navPolyline && this.activeMission) {\r\n                                this.navPolyline.setLatLngs([[this.pos.lat, this.pos.lng], [this.activeMission.lat, this.activeMission.lng]]);\r\n                            }\r\n                        }, 2000);\r\n                    }\r\n                };\r\n\r\n                const isSecure = window.location.protocol === 'https:' || window.location.hostname === 'localhost' || window.location.hostname === '127.0.0.1';\r\n\r\n                if (navigator.geolocation && isSecure) {\r\n                    navigator.geolocation.watchPosition((position) => {\r\n                        this.pos.lat = position.coords.latitude;\r\n                        this.pos.lng = position.coords.longitude;\r\n                        if (this.rescuerMarker) this.rescuerMarker.setLatLng([this.pos.lat, this.pos.lng]);\r\n                        if (this.navPolyline && this.activeMission) {\r\n                            this.navPolyline.setLatLngs([[this.pos.lat, this.pos.lng], [this.activeMission.lat, this.activeMission.lng]]);\r\n                        }\r\n                    }, (err) => {\r\n                        console.warn(\"Rescuer GPS error, falling back to simulation:\", err);\r\n                        startSimulation();\r\n                    }, { enableHighAccuracy: true, maximumAge: 5000, timeout: 10000 });\r\n                } else {\r\n                    console.warn(\"Insecure context or no geolocation, using simulation.\");\r\n                    startSimulation();\r\n                }\r\n\r\n                const runSync = async () => {\r\n\r\n                    try {\r\n                        const res = await fetch(`${this.API}/sync`, {\r\n                            method: 'POST',\r\n                            headers: { 'Content-Type': 'application/json' },\r\n                            body: JSON.stringify({\r\n                                phone: this.user.phone,\r\n                                deviceId: this.user.serial_number || 'MEM-01',\r\n                                location: { lat: this.pos.lat, lng: this.pos.lng, groupId: 1 }\r\n                            })\r\n                        });\r\n                        if (res.ok) {\r\n                            this.updateNetUI(true);\r\n                        } else {\r\n                            this.updateNetUI(false);\r\n                        }\r\n                        const data = await res.json();\r\n\r\n                        // Restore interrupted task if backend has it and we don't have an active mission\r\n                        if (data.user?.interrupted_task_id && !this.activeMission && !this.interruptedMission) {\r\n                            // Fetch task list or search for this ID\r\n                            // For simplicity in web preview, we'll try to find it in history/active data next refresh\r\n                            // or just use the ID to fetch it if needed. \r\n                            // In this preview, we usually rely on 'refresh' to populate task list.\r\n                        }\r\n\r\n                        if (data.commands) data.commands.forEach(c => this.handleCommand(c));\r\n\r\n                        // Update refresh interval from server\r\n                        if (data.refresh_interval) {\r\n                            const newInterval = parseInt(data.refresh_interval);\r\n                            if (newInterval > 0 && newInterval !== this.refreshInterval) {\r\n                                console.log(`[Rescuer] Sync interval updated to ${newInterval}s`);\r\n                                this.refreshInterval = newInterval;\r\n                                const el = document.getElementById('dispSyncInterval');\r\n                                if (el) el.innerText = this.refreshInterval + 's (Sync Active)';\r\n                            }\r\n                        }\r\n                    } catch (e) { \r\n                        this.updateNetUI(false);\r\n                    }\r\n\r\n                    // Schedule next sync\r\n                    this.syncTimer = setTimeout(runSync, this.refreshInterval * 1000);\r\n                };\r\n\r\n                runSync();\r\n            },\r\n\r\n            connectWS() {\r\n                if (this.ws) {\r\n                    try {\r\n                        this.ws.onclose = null;\r\n                        this.ws.onerror = null;\r\n                        this.ws.close();\r\n                    } catch(e) {}\r\n                }\r\n                if (!this.WS_URL) {\r\n                    this.updateNetUI(false);\r\n                    try {\r\n                        window.ReactNativeWebView.postMessage(JSON.stringify({ type: 'WS_STATUS', connected: false }));\r\n                    } catch(e) {}\r\n                    return;\r\n                }\r\n                const ws = new WebSocket(this.WS_URL);\r\n                this.ws = ws;\r\n                ws.onopen = () => {\r\n                    console.log('Connected to WS');\r\n                    ws.send(JSON.stringify({ type: 'REGISTER', deviceId: this.user?.device_id || 'RESCUER_' + Date.now() }));\r\n                    this.refresh();\r\n                    this.updateNetUI(true);\r\n                    try {\r\n                        window.ReactNativeWebView.postMessage(JSON.stringify({ type: 'WS_STATUS', connected: true }));\r\n                    } catch(e) {}\r\n                };\r\n                ws.onmessage = (e) => {\r\n                    const msg = JSON.parse(e.data);\r\n                    \r\n                    if (msg.type === 'USER_DISABLED' || msg.type === 'FORCE_LOGOUT') {\r\n                        this.toast(msg.data?.reason || 'SESSION EXPIRED: PLEASE LOGIN AGAIN', '🚫');\r\n                        setTimeout(() => this.logout(), 2000);\r\n                        return;\r\n                    }\r\n\r\n                    const updateTypes = ['NEW_RESCUE_REQUEST', 'COMMAND_STATUS_UPDATE', 'COMMAND_COMPLETED', 'RESCUE_REQUEST_UPDATE', 'RESCUE_REQUEST_ACCEPTED', 'NEW_COMMAND'];\r\n\r\n                    if (updateTypes.includes(msg.type)) {\r\n                        this.refresh();\r\n\r\n                        // If it's a direct command, handle the modal/notification\r\n                        if (msg.type === 'NEW_COMMAND' && msg.data) {\r\n                            this.handleCommand(msg.data);\r\n                        }\r\n\r\n                        // If current mission is completed by admin, clear it\r\n                        if ((msg.type === 'COMMAND_STATUS_UPDATE' || msg.type === 'COMMAND_COMPLETED') && msg.data?.status === 'completed') {\r\n                            if (this.activeMission && (this.activeMission.id === msg.data.id || ('CMD-' + this.activeMission.id) === msg.data.id)) {\r\n                                this.activeMission = null;\r\n                                document.getElementById('missionBanner').style.display = 'none';\r\n                                if (this.navPolyline) this.map.removeLayer(this.navPolyline);\r\n                                this.refresh();\r\n                            }\r\n                        }\r\n                    }\r\n                };\r\n                ws.onerror = () => {\r\n                    this.updateNetUI(false);\r\n                    try {\r\n                        window.ReactNativeWebView.postMessage(JSON.stringify({ type: 'WS_STATUS', connected: false }));\r\n                    } catch(e) {}\r\n                };\r\n                ws.onclose = () => {\r\n                    this.updateNetUI(false);\r\n                    try {\r\n                        window.ReactNativeWebView.postMessage(JSON.stringify({ type: 'WS_STATUS', connected: false }));\r\n                    } catch(e) {}\r\n                    if (this.ws === ws) {\r\n                        setTimeout(() => this.connectWS(), 5000);\r\n                    }\r\n                };\r\n            },\r\n\r\n            handleCommand(c) {\r\n                if (c.status === 'completed' || c.status === 'declined') return;\r\n\r\n                // Security/Targeting check: only show if for this rescuer or their group\r\n                const myPhone = this.user?.phone;\r\n                const myDeviceId = this.user?.device_id;\r\n                const myGroups = (this.user?.groups || []).map(g => Number(g.id || g.group_id));\r\n\r\n                // Match phone normalized (last 10 digits) or device_id directly\r\n                const myPhoneClean = (myPhone || '').replace(/\\D/g,'').slice(-10);\r\n                const tpClean = (c.target_phone || '').replace(/\\D/g,'').slice(-10);\r\n                const isTargeted = c.target_phone && (\r\n                    c.target_phone === myPhone ||\r\n                    c.target_phone === myDeviceId ||\r\n                    c.target_phone === String(this.user?.id) ||\r\n                    (myPhoneClean && tpClean && tpClean === myPhoneClean)\r\n                );\r\n                const isGroupTargeted = (c.group_id && myGroups.includes(Number(c.group_id)));\r\n                const isGeneral = (!c.target_phone && !c.group_id);\r\n\r\n                if (!isTargeted && !isGroupTargeted && !isGeneral) {\r\n                    return; // Not for us\r\n                }\r\n\r\n                // Track commands by ID and timestamp to handle updates\r\n                const lastSeen = this.commandState[c.id];\r\n                if (lastSeen === c.updated_at) return;\r\n                this.commandState[c.id] = c.updated_at;\r\n\r\n                // Silent update if it's the current active mission\r\n                if (this.activeMission && (String(this.activeMission.id) === String(c.id))) {\r\n                    this.toast('MISSION UPDATED BY HQ', 'ℹ️');\r\n                    this.startMission(c.id, this.activeMission.type, this.activeMission.sector, 0, 0, 'command'); // startMission will parse payload\r\n                    return;\r\n                }\r\n\r\n                if (c.status === 'accepted' || c.status === 'ongoing') return;\r\n\r\n                let payload = {};\r\n                try { payload = JSON.parse(c.command_payload); } catch (e) { }\r\n\r\n                const isCrit = c.priority === 'critical' || c.command_type === 'critical';\r\n                const modal = document.createElement('div');\r\n                modal.style.cssText = `\r\n                    position: fixed; top: 0; left: 0; right: 0; bottom: 0;\r\n                    background: rgba(0,0,0,0.8); z-index: 10000;\r\n                    display: flex; align-items: center; justify-content: center; padding: 20px;\r\n                `;\r\n\r\n                modal.innerHTML = `\r\n                    <div style=\"background: #1e293b; padding: 20px; border-radius: 12px; border: 1px solid ${isCrit ? '#ef4444' : '#3b82f6'}; width: 100%; max-width: 400px; text-align: center;\">\r\n                        <h2 style=\"color: ${isCrit ? '#ef4444' : '#3b82f6'}; margin-top: 0;\">${isCrit ? '🚨 CRITICAL DIRECTIVE' : '📢 NEW TASK'}</h2>\r\n                        <p style=\"color: #fff; font-size: 16px; margin: 10px 0;\">${payload.message || 'New task assigned from HQ'}</p>\r\n                        \r\n                        ${c.image_url ? `\r\n                            <div style=\"width:100%; height:140px; border-radius:8px; overflow:hidden; margin-bottom:12px; border:1px solid #334155;\">\r\n                                <img src=\"http://${core.serverIp || window.location.hostname || '127.0.0.1'}:3001${c.image_url}\" style=\"width:100%; height:100%; object-fit:cover;\">\r\n                            </div>\r\n                        ` : ''}\r\n\r\n                        ${c.rescue_details ? (() => {\r\n                        try {\r\n                            const d = typeof c.rescue_details === 'string' ? JSON.parse(c.rescue_details) : c.rescue_details;\r\n                            if (d.comments) {\r\n                                return `<p style=\"font-size:12px; color:#cbd5e1; font-style:italic; margin-bottom:12px; background:rgba(255,255,255,0.05); padding:8px; border-radius:8px;\">\"${d.comments}\"</p>`;\r\n                            }\r\n                        } catch (e) { }\r\n                        return '';\r\n                    })() : ''}\r\n\r\n                        <p style=\"color: #94a3b8; font-size: 14px; margin-bottom: 20px;\">Priority: ${c.priority || c.command_type || 'normal'}</p>\r\n                        <div style=\"display: flex; gap: 10px; justify-content: center;\">\r\n                            <button class=\"btn-action btn-primary\" onclick=\"core.acceptCommandFromModal('${c.id}', ${payload.lat || 0}, ${payload.lng || 0}); this.closest('div').parentElement.parentElement.remove();\">ACCEPT</button>\r\n                            <button class=\"btn-action btn-secondary\" onclick=\"core.declineCommandFromModal('${c.id}'); this.closest('div').parentElement.parentElement.remove();\">DECLINE</button>\r\n                        </div>\r\n                    </div>\r\n                `;\r\n                document.body.appendChild(modal);\n                if(window.ReactNativeWebView) window.ReactNativeWebView.postMessage(JSON.stringify({type: \\'PLAY_SOUND\\', sound: \\'siren_loop\\'}));\r\n            },\r\n\r\n            async acceptCommandFromModal(id, lat, lng) {\n                if(window.ReactNativeWebView) window.ReactNativeWebView.postMessage(JSON.stringify({type: \\'STOP_SOUND\\'}));\r\n                this.toast('ACCEPTING TASK...', '⏳');\r\n                try {\r\n                    await fetch(`${this.API}/commands/${id}/status`, {\r\n                        method: 'PUT',\r\n                        headers: { 'Content-Type': 'application/json' },\r\n                        body: JSON.stringify({ status: 'accepted', rescuer_phone: this.user.phone })\r\n                    });\r\n\r\n                    const isCrit = c.priority === 'critical' || c.command_type === 'critical';\r\n                    if (isCrit && this.activeMission && !['sos', 'medical', 'pregnancy', 'critical'].includes(this.activeMission.type.toLowerCase())) {\r\n                        this.interruptedMission = { ...this.activeMission };\r\n                        fetch(`${this.API}/users/${this.user.id}/interrupted-task`, {\r\n                            method: 'PUT',\r\n                            headers: { 'Content-Type': 'application/json' },\r\n                            body: JSON.stringify({ task_id: this.activeMission.id }),\r\n                        }).catch(() => { });\r\n                    }\r\n\r\n                    this.refresh();\r\n                    if (lat && lng) {\r\n                        this.activeMission = { id: 'CMD-' + id, type: 'command', sector: 'Direct HQ Order', lat, lng };\r\n                        document.getElementById('missionBanner').style.display = 'flex';\r\n                        document.getElementById('missType').innerText = `HQ COMMAND`;\r\n                        document.getElementById('missLoc').innerText = 'Proceed to Target Point';\r\n                        if (this.navPolyline) this.map.removeLayer(this.navPolyline);\r\n                        this.navPolyline = L.polyline([[this.pos.lat, this.pos.lng], [lat, lng]], {\r\n                            color: '#ef4444', weight: 6, opacity: 0.8, dashArray: '10, 15'\r\n                        }).addTo(this.map);\r\n                        this.map.fitBounds(this.navPolyline.getBounds(), { padding: [50, 50] });\r\n                    }\r\n                    this.toast('TASK ACCEPTED', '✅');\r\n                } catch (e) {\r\n                    this.toast('FAILED TO ACCEPT', '❌');\r\n                }\r\n            },\r\n\r\n            async declineCommandFromModal(id) {\n                if(window.ReactNativeWebView) window.ReactNativeWebView.postMessage(JSON.stringify({type: \\'STOP_SOUND\\'}));\r\n                this.toast('DECLINING TASK...', '⏳');\r\n                try {\r\n                    await fetch(`${this.API}/commands/${id}/status`, {\r\n                        method: 'PUT',\r\n                        headers: { 'Content-Type': 'application/json' },\r\n                        body: JSON.stringify({ status: 'declined', rescuer_phone: this.user.phone })\r\n                    });\r\n                    this.refresh();\r\n                    this.toast('TASK DECLINED', '❌');\r\n                } catch (e) {\r\n                    this.toast('FAILED TO DECLINE', '❌');\r\n                }\r\n            },\r\n\r\n            locateSelf() {\r\n                this.map.setView([this.pos.lat, this.pos.lng], 16);\r\n            },\r\n\r\n            toggleMapType() {\r\n                this.toast('Switching to Satellite View...', '🗺️');\r\n            },\r\n\r\n            toast(msg, icon = 'ℹ️') {\r\n                const t = document.createElement('div');\r\n                t.style.cssText = `position:absolute; bottom:110px; left:50%; transform:translateX(-50%); background:#0f172a; color:white; padding:14px 24px; border-radius:30px; font-size:14px; font-weight:800; z-index:10000; box-shadow:var(--shadow-lg); display:flex; align-items:center; gap:12px; animation:pop 0.3s ease-out;`;\r\n                t.innerHTML = `<span>${icon}</span> ${msg}`;\r\n                document.querySelector('.phone-inner').appendChild(t);\r\n                setTimeout(() => t.remove(), 3500);\r\n            },\r\n\r\n            showLoader(val) { document.getElementById('loader').style.display = val ? 'flex' : 'none'; }\r\n        };\r\n\r\n        // Leaflet CSS Override\r\n        const style = document.createElement('style');\r\n        style.innerHTML = `.leaflet-container { background: #f1f5f9 !important; } .leaflet-bar { border: none !important; } .leaflet-bar a { background: white !important; border: 1px solid #e2e8f0 !important; color: #1e293b !important; }`;\r\n        document.head.appendChild(style);\r\n\r\n        window.core = core;\r\n        window.onImageCaptured = (base64, id) => {\r\n            core.capturedImages[id] = base64;\r\n\r\n            // Update banner camera button icon\r\n            const bannerBtn = document.getElementById('bannerCameraBtn');\r\n            if (bannerBtn && (id === '__banner__' || (core.activeMission && String(core.activeMission.id) === String(id)))) {\r\n                bannerBtn.textContent = '✅';\r\n                bannerBtn.classList.add('captured');\r\n            }\r\n\r\n            // Update card camera button\r\n            const cardBtn = document.getElementById('camBtn_' + id);\r\n            if (cardBtn) {\r\n                cardBtn.textContent = '✅ Photo';\r\n                cardBtn.classList.add('captured');\r\n            }\r\n\r\n            core.toast('📷 Photo attached via Native App!', '✅');\r\n        };\r\n        if (document.readyState === 'complete' || document.readyState === 'interactive') {\r\n            core.init();\r\n        } else {\r\n            window.addEventListener('DOMContentLoaded', () => core.init());\r\n        }\r\n    </script>\r\n</body>\r\n\r\n</html>";
